def _arb_atom_kombi_tipi(ilac_adi: str, etkin_madde: str
                          ) -> Tuple[bool, bool, bool, bool]:
    """ARB ilaç tipi tespiti.

    Returns: (is_kombi, hct_var, ccb_var, ace_var)
    """
    aday = (etkin_madde + ' ' + ilac_adi).upper()
    is_kombi = ('/' in etkin_madde.upper()) or (' VE ' in f' {etkin_madde.upper()} ')
    if not is_kombi and any(t in ilac_adi.upper() for t in _ARB_KOMBI_TICARI):
        is_kombi = True
    hct_var = (
        any(k in aday for k in _ARB_HCT_KEYS)
        or ' HCT' in (' ' + aday + ' ')
        or '/HCT' in aday
        or any(k in aday for k in _ARB_DIURETIK_GENEL_KEYS)
    )
    ccb_var = any(k in aday for k in _ARB_CCB_KEYS)
    ace_var = any(k in aday for k in _ARB_ACE_KEYS)
    return is_kombi, hct_var, ccb_var, ace_var


def _arb_atom_aile_hekimi(doktor_brans: str, kurum_adi: str,
                           tesis_kodu: str,
                           doktor_adi: str = '') -> Tuple[bool, str]:
    """Aile hekimi yetkisi 4 yoldan (branş/kurum/tesis kodu/kronik hastalık hekimi).

    Returns: (yetkili_mi, neden_metni)
    """
    du = doktor_brans.upper()
    ku = kurum_adi.upper()
    nedenler = []
    if ('AILE HEK' in du or 'AİLE HEK' in du):
        nedenler.append('branşta aile hekimliği sertifikası')
    if ku and (
            'AILE SAGLIGI' in ku or 'AİLE SAĞLIĞI' in ku
            or 'AILE SAĞLIĞI' in ku or 'AİLE SAGLIGI' in ku
            or 'AILE HEKIMLIGI' in ku or 'AİLE HEKİMLİĞİ' in ku
            or any(tok in ku.split() for tok in ('ASM', 'AHM'))):
        nedenler.append(f'kurum: {kurum_adi[:50]}')
    if tesis_kodu and tesis_kodu in AILE_HEKIMLIGI_TESIS_KODLARI:
        nedenler.append(f'tesis kodu: {tesis_kodu}')
    khh_var, khh_etiket = _kronik_hastalik_hekimi_tespit(doktor_adi, tesis_kodu)
    if khh_var:
        nedenler.append(khh_etiket)
    return (bool(nedenler), ' + '.join(nedenler))


def _arb_atom_monoterapi_ibaresi(metin_lower_i: str) -> Tuple[bool, str]:
    """Raporda 'monoterapi yetersiz' ibaresi var mı.

    metin_lower_i: i/ı/I/İ → 'i' normalize edilmiş metin.
    Returns: (var_mi, eslesen_ibare).
    """
    # 1) Tek-anahtar yetersizlik ifadeleri
    for ibare in (
        'monoterapiye dirençli', 'monoterapiye direncli',
        'monoterapiye yanit',
        'kombine terapi endikasyon', 'kombine tedavi endikasyon',
        'kombine tedavi gerek', 'kombine tedavi şart', 'kombine tedavi sart',
        'kombine tedavi endike', 'kombinasyon tedavi gerek',
        'ikili tedavi gerek', 'üçlü tedavi gerek', 'uclu tedavi gerek',
    ):
        if ibare in metin_lower_i:
            return True, ibare
    if 'monoterapi' in metin_lower_i:
        return True, 'monoterapi'
    kompozitler = (
        (('tek ilaç', 'tek ilac', 'tek antihipertansif'),
         ('yeter', 'kontrol', 'sağlanama', 'saglanama',
          'yanit', 'alinama')),
        (('kan basinci', 'tansiyon'),
         ('kontrol altina alinama',
          'yeterli kontrol sağlanama', 'yeterli kontrol saglanama',
          'kontrol edilemem')),
        (('kombinasyon',),
         ('gerek', 'şart', 'sart', 'endike')),
        (('yeterli',),
         ('kontrol sağlanama', 'kontrol saglanama')),
    )
    for anchors, helpers in kompozitler:
        if (any(a in metin_lower_i for a in anchors)
                and any(h in metin_lower_i for h in helpers)):
            return True, next(a for a in anchors if a in metin_lower_i)
    return False, ''


def kontrol_arb_ek4f_m51(ilac_sonuc: Dict) -> KontrolRaporu:
    """
    SUT EK-4/F Madde 51 (1300/51) — Anjiotensin Reseptör Blokerleri ve Kombinasyonları

    Kapsam:
      İrbesartan, Kandesartan, Losartan, Telmisartan, Valsartan, Olmesartan,
      Eprosartan Mesilat, Rilmeniden, Moksonidin + bunların diğer
      antihipertansiflerle (CCB / ACE-i) kombinasyonları.

    SGK 17.10.2016 ISTISNASI — Diüretik (HCT) kombinasyonları:
      ARB + HCT (hidroklorotiazid) sabit kombinasyonları SGK'nın 17.10.2016
      tarihli resmi duyurusu ile bu kapsamın DIŞINDA tutulmuştur. Birebir
      lafız: "diüretikli kombinasyonların bu kapsamda bulunmadığı". Yani
      raporlu ARB+HCT kombilerinde "monoterapi yetersizliği" ibaresi aranmaz.
      3'lü kombilerde (ARB+CCB+HCT) CCB içerdiği için istisna geçersizdir.

    Kurallar (SUT metni + 17.10.2016 duyurusu):
      1. Mono ARB raporlu: Raporda doz/uygulama planı/süre belirtme zorunluluğu
         BULUNMAMAKTADIR. Rapor yeterlidir.
      2. ARB+HCT kombi raporlu: Diüretik istisnası — rapor yeterli, monoterapi
         ibaresi aranmaz.
      3. ARB+CCB / ARB+ACE / 3'lü kombi raporlu: Hastanın "monoterapi ile kan
         basıncının yeterli oranda kontrol altına alınamadığı" raporda
         belirtilmelidir.
      4. Raporsuz: ARB ve kombinasyonları ayda EN FAZLA 1 KUTU olarak
         AİLE HEKİMLERİNCE reçete edilebilir.

    Karar tablosu:
      RAPORLU + MONO                                  → UYGUN
      RAPORLU + KOMBİ_HCT (sadece ARB+HCT)            → UYGUN (diüretik istisnası)
      RAPORLU + KOMBİ_DIGER + monoterapi ibaresi VAR  → UYGUN
      RAPORLU + KOMBİ_DIGER + monoterapi ibaresi YOK  → ŞÜPHELİ
      RAPORSUZ + aile hekimi + ≤1 kutu                → UYGUN
      RAPORSUZ + (aile hekimi değil) ya da >1 kutu    → UYGUN_DEGIL
    """
    ilac_adi = (ilac_sonuc.get('ilac_adi') or '').upper()
    etkin_madde = (ilac_sonuc.get('etkin_madde') or '').upper()
    rapor_kodu = (ilac_sonuc.get('rapor_kodu') or '').strip()
    doktor_brans = (ilac_sonuc.get('doktor_uzmanligi') or '').upper()
    kurum_adi = (ilac_sonuc.get('kurum_adi') or '').upper()
    tesis_kodu = str(ilac_sonuc.get('tesis_kodu') or '').strip()

    # Kutu sayısı parse
    kutu_raw = ilac_sonuc.get('kutu_sayisi')
    if kutu_raw is None:
        kutu_raw = ilac_sonuc.get('miktar', '')
    try:
        kutu = float(str(kutu_raw).replace(',', '.')) if str(kutu_raw).strip() else 0.0
    except (ValueError, TypeError):
        kutu = 0.0

    tum_metin = _tum_metinleri_birlesir(ilac_sonuc) or ''
    sut_kurali = 'SUT EK-4/F Madde 51 (1300/51) — ARB ve kombinasyonları'

    # Atomik analizler
    is_kombi, hct_var, ccb_var, ace_var = _arb_atom_kombi_tipi(ilac_adi, etkin_madde)
    is_hct_only_kombi = is_kombi and hct_var and not ccb_var and not ace_var
    is_mono = not is_kombi
    is_raporlu = bool(rapor_kodu)
    doktor_adi = (ilac_sonuc.get('doktor_adi') or '').strip()
    aile_hekimi, yetki_kaynagi = _arb_atom_aile_hekimi(
        doktor_brans, kurum_adi, tesis_kodu, doktor_adi)
    brans_pratisyen = ('PRATISYEN' in doktor_brans or 'PRATİSYEN' in doktor_brans)
    kutu_asildi = kutu > 1

    detaylar = {
        'ilac_adi': ilac_adi, 'etkin_madde': etkin_madde,
        'rapor_kodu': rapor_kodu, 'doktor_brans': doktor_brans,
        'kutu': kutu,
        'tip': ('KOMBI_HCT' if is_hct_only_kombi
                else ('KOMBI' if is_kombi else 'MONO')),
        'hct_var': hct_var, 'ccb_var': ccb_var, 'ace_var': ace_var,
        'kurum_adi': kurum_adi, 'tesis_kodu': tesis_kodu,
        'aile_hekimi': aile_hekimi,
    }

    # ═══════════════════════════════════════════════════════════════════
    # 4-YOLAK PARALEL MODEL (SUT EK-4/F m.51: Y1 ∨ Y2 ∨ Y3 ∨ Y4)
    # ═══════════════════════════════════════════════════════════════════
    # SUT lafzı 4 ALTERNATİF yol içerir — aralarında VEYA, içlerinde VE:
    #   Y-1: Mono ARB raporlu                          (raporlu + mono)
    #   Y-2: ARB+HCT raporlu — SGK 17.10.2016 istisnası (raporlu + HCT-only)
    #   Y-3: ARB+CCB/ACE/3'lü raporlu + monoterapi      (raporlu + kombi diğer)
    #   Y-4: Raporsuz + aile hekimi + ayda ≤1 kutu
    # Üst-VEYA matematiği: en az 1 yolun TÜM atomları VAR ise → UYGUN
    # Render: `Y-` prefix'li grup adları → _klasik_yolak_modu_ciz otomatik
    # 4 paralel kol çizer (klop pattern).
    # ═══════════════════════════════════════════════════════════════════
    sartlar: List[SartSonuc] = []
    brans_pratisyen = ('PRATISYEN' in doktor_brans
                       or 'PRATİSYEN' in doktor_brans)
    detaylar['yetki_kaynagi'] = yetki_kaynagi

    # ── İlaç tipi (bilgi grubu — hesaplama dışı) ──────────────────────
    g_tip = 'İlaç tipi (bilgi)'
    sartlar.append(SartSonuc(
        'ARB etken madde',
        SartDurumu.VAR,
        f'Etken madde: {etkin_madde or ilac_adi}',
        'etkin_madde/ilac_adi', grup=g_tip))
    if is_kombi:
        kombi_turu = ('HCT (diüretik)' if is_hct_only_kombi
                       else ('CCB+HCT 3\'lü' if (ccb_var and hct_var)
                             else ('ACE+HCT 3\'lü' if (ace_var and hct_var)
                                   else ('CCB' if ccb_var
                                         else ('ACE-i' if ace_var
                                               else 'belirsiz')))))
        sartlar.append(SartSonuc(
            'Kombi türü',
            SartDurumu.VAR, kombi_turu, 'etkin_madde', grup=g_tip))
    else:
        sartlar.append(SartSonuc(
            'Kombi türü', SartDurumu.YOK, 'Mono ARB', 'etkin_madde',
            grup=g_tip))

    # ── Y-1: Mono ARB raporlu ─────────────────────────────────────────
    g_y1 = 'Y-1: Mono ARB raporlu'
    sartlar.append(SartSonuc(
        'Mono ARB ilaç (kombi DEĞİL)',
        SartDurumu.VAR if is_mono else SartDurumu.YOK,
        ('Mono ARB' if is_mono else 'Kombi ARB (içerik: belirsiz)'),
        'etkin_madde', grup=g_y1))
    sartlar.append(SartSonuc(
        'Rapor kodu VAR',
        SartDurumu.VAR if is_raporlu else SartDurumu.YOK,
        (f'rapor_kodu={rapor_kodu}' if is_raporlu else 'Raporsuz'),
        'rap_kod', grup=g_y1))

    # ── Y-2: ARB+HCT raporlu (SGK 17.10.2016 diüretik istisnası) ──────
    g_y2 = 'Y-2: ARB+HCT raporlu (SGK 17.10.2016 istisnası)'
    sartlar.append(SartSonuc(
        'Sadece ARB+HCT diüretik kombi (CCB/ACE içermez)',
        SartDurumu.VAR if is_hct_only_kombi else SartDurumu.YOK,
        ('SGK 17.10.2016 — 1300/51 kapsam DIŞINDA'
         if is_hct_only_kombi
         else ('Mono ARB' if is_mono
               else ('CCB/ACE/3\'lü içeriyor — istisna geçersiz'))),
        'etkin_madde', grup=g_y2))
    sartlar.append(SartSonuc(
        'Rapor kodu VAR',
        SartDurumu.VAR if is_raporlu else SartDurumu.YOK,
        (f'rapor_kodu={rapor_kodu}' if is_raporlu else 'Raporsuz'),
        'rap_kod', grup=g_y2))

    # ── Y-3: ARB+CCB/ACE/3'lü raporlu + monoterapi ibaresi ────────────
    g_y3 = 'Y-3: ARB+CCB/ACE/3\'lü raporlu + monoterapi ibaresi'
    is_kombi_diger = is_kombi and not is_hct_only_kombi
    sartlar.append(SartSonuc(
        'ARB kombi (CCB ∨ ACE ∨ 3\'lü — HCT-only DEĞİL)',
        SartDurumu.VAR if is_kombi_diger else SartDurumu.YOK,
        ('Kombi tipi: ' + ('CCB' if ccb_var and not hct_var
                            else ('ACE-i' if ace_var and not hct_var
                                  else '3\'lü/diğer'))
         if is_kombi_diger
         else ('Sadece ARB+HCT — Y-2 yolu' if is_hct_only_kombi
               else 'Mono ARB — Y-1 yolu')),
        'etkin_madde', grup=g_y3))
    sartlar.append(SartSonuc(
        'Rapor kodu VAR',
        SartDurumu.VAR if is_raporlu else SartDurumu.YOK,
        (f'rapor_kodu={rapor_kodu}' if is_raporlu else 'Raporsuz'),
        'rap_kod', grup=g_y3))
    # Monoterapi ibaresi (KRİTİK — bypass adayı)
    ml = (tum_metin.replace('İ', 'i').replace('I', 'i')
                   .replace('ı', 'i').lower())
    mono_ibare_var, eslesen_kelime = _arb_atom_monoterapi_ibaresi(ml)
    sartlar.append(SartSonuc(
        'Raporda "monoterapi ile kan basıncı sağlanamadı" ibaresi',
        SartDurumu.VAR if mono_ibare_var else SartDurumu.YOK,
        (f'İbare: "{eslesen_kelime}"' if mono_ibare_var
         else 'İbare aktif raporda yok'),
        'rapor_metni', grup=g_y3))

    # ── Y-4: Raporsuz + aile hekimi + ayda ≤1 kutu ────────────────────
    g_y4 = 'Y-4: Raporsuz + aile hekimi + ayda ≤1 kutu'
    sartlar.append(SartSonuc(
        'Rapor kodu YOK (raporsuz reçete)',
        SartDurumu.VAR if not is_raporlu else SartDurumu.YOK,
        ('Raporsuz' if not is_raporlu else f'rapor_kodu={rapor_kodu}'),
        'rap_kod', grup=g_y4))
    sartlar.append(SartSonuc(
        'Aile hekimi yetkisi (branş ∨ kurum ∨ tesis)',
        SartDurumu.VAR if aile_hekimi
        else (SartDurumu.KONTROL_EDILEMEDI if brans_pratisyen
              else SartDurumu.YOK),
        (f'Yetki: {yetki_kaynagi}' if aile_hekimi
         else ('Pratisyen — sertifika/ASM tespit edilemedi'
               if brans_pratisyen
               else f'Branş: {doktor_brans or "?"}, '
                    f'Kurum: {kurum_adi or "?"}')),
        'doktor_uzmanligi/kurum/tesis', grup=g_y4))
    sartlar.append(SartSonuc(
        'Aylık kutu sayısı ≤ 1',
        SartDurumu.YOK if kutu_asildi else SartDurumu.VAR,
        f'Kutu: {kutu:g}', 'kutu_sayisi', grup=g_y4))

    # ── DİĞER RAPOR BYPASS — Y-3 monoterapi atomu için ────────────────
    # Aktif raporda ibare yok ama hastanın diğer reçetelerine ilintili
    # raporlardan birinde varsa → atom VAR + bypass_kaynak.
    # ÖNCELİK: Botanik EOS (RaporAnaAciklamalar), sonra cache fallback.
    bypass_kaydi = None
    if not mono_ibare_var:
        bypass_tc = (ilac_sonuc.get('hasta_tc') or '').strip()
        bypass_tno = (ilac_sonuc.get('rapor_takip_no') or '').strip()
        if bypass_tc:
            try:
                from recete_kontrol.diger_rapor_bypass import (
                    eos_raporlarda_ibare_ara, gecmis_raporlarda_ibare_ara,
                    IBARELER_ARB_MONOTERAPI)
                # 1) Botanik EOS önce
                bypass_kaydi = eos_raporlarda_ibare_ara(
                    bypass_tc, list(IBARELER_ARB_MONOTERAPI),
                    aktif_rapor_aciklama=tum_metin)
                # 2) Cache fallback
                if bypass_kaydi is None:
                    bypass_kaydi = gecmis_raporlarda_ibare_ara(
                        bypass_tc, list(IBARELER_ARB_MONOTERAPI),
                        aktif_rapor_takip_no=bypass_tno,
                        kategori='HIPERTANSIYON')
            except Exception as e:
                logger.debug("ARB monoterapi bypass sorgu hatası: %s", e)
        if bypass_kaydi:
            for sart in sartlar:
                if 'monoterapi' in sart.ad.lower() and sart.grup == g_y3:
                    sart.durum = SartDurumu.VAR
                    sart.neden = f'BYPASS: {bypass_kaydi["ozet"]}'
                    sart.bypass_kaynak = bypass_kaydi["ozet"]
                    break

    # ── ÜST-VEYA matematiği: en az 1 yolun tüm atomları VAR ise UYGUN ──
    yolaklar = [
        ('Y-1', g_y1, 'Mono ARB raporlu'),
        ('Y-2', g_y2, 'ARB+HCT raporlu (diüretik istisnası)'),
        ('Y-3', g_y3, 'Kombi raporlu + monoterapi ibaresi'),
        ('Y-4', g_y4, 'Raporsuz + aile hekimi + ≤1 kutu'),
    ]
    aktif_yol_bilgi = None     # (yol_kod, yol_ad)
    bypass_yol = False         # bypass'lı atomla tamamlanmış yol mu?
    yol_ke_var = False
    for yol_kod, yol_grup, yol_ad in yolaklar:
        yol_atomlari = [s for s in sartlar if s.grup == yol_grup]
        durumlar = [s.durum for s in yol_atomlari]
        if all(d == SartDurumu.VAR for d in durumlar):
            aktif_yol_bilgi = (yol_kod, yol_ad)
            if any(getattr(s, 'bypass_kaynak', None) for s in yol_atomlari):
                bypass_yol = True
            break
        if SartDurumu.KONTROL_EDILEMEDI in durumlar:
            yol_ke_var = True

    if aktif_yol_bilgi:
        yol_kod, yol_ad = aktif_yol_bilgi
        if bypass_yol and bypass_kaydi:
            return KontrolRaporu(
                sonuc=KontrolSonucu.DIGER_RAPOR_UYGUN,
                mesaj=(f'{yol_kod} ({yol_ad}) — aktif raporda monoterapi '
                       f'ibaresi yok; hastanın diğer raporunda bulundu: '
                       f'{bypass_kaydi["ozet"]}'),
                detaylar={**detaylar, 'bypass': bypass_kaydi,
                          'aktif_yol': yol_kod},
                sut_kurali=sut_kurali, sartlar=sartlar,
                aranan_ibare='Monoterapi yetersizliği ibaresi (diğer raporda bulundu)',
                bulunan_metin=bypass_kaydi.get('snippet', ''))
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN,
            mesaj=f'{yol_kod} ({yol_ad}) — tüm şartlar sağlandı',
            detaylar={**detaylar, 'aktif_yol': yol_kod},
            sut_kurali=sut_kurali, sartlar=sartlar,
            aranan_ibare=yol_ad)

    if yol_ke_var:
        return KontrolRaporu(
            sonuc=KontrolSonucu.KONTROL_EDILEMEDI,
            mesaj=('Hiçbir yolun (Y1∨Y2∨Y3∨Y4) tüm şartları net olarak '
                   'sağlanmadı; bir yolda KE atom var — manuel kontrol'),
            detaylar=detaylar, sut_kurali=sut_kurali, sartlar=sartlar,
            uyari='SUT EK-4/F m.51 — 4 yoldan biri eksik/şüpheli',
            aranan_ibare='Y1: mono+rap ∨ Y2: HCT+rap ∨ Y3: kombi+rap+mono ibare ∨ Y4: aile hek.+1 kutu')

    return KontrolRaporu(
        sonuc=KontrolSonucu.UYGUN_DEGIL,
        mesaj=('SUT EK-4/F m.51: 4 yoldan hiçbiri tamamlanmadı '
               '(Y1 mono+rap, Y2 HCT+rap, Y3 kombi+rap+monoterapi ibare, '
               'Y4 raporsuz+aile hek+≤1 kutu)'),
        detaylar=detaylar, sut_kurali=sut_kurali, sartlar=sartlar,
        uyari='ARB için en az 1 ödeme yolu sağlanmalıdır',
        aranan_ibare='Y1 ∨ Y2 ∨ Y3 ∨ Y4 (alternatif yollar)')


# Hastanın "diğer aktif raporlarında" hangi tanı kategorilerine bakılacağını
# tanımlayan keyword sözlüğü. Her SUT kontrol wrapper'ı kendi ilgi alanını
# parametre olarak verir; karara karışmaz, sadece UYGUN_DEĞİL/ŞÜPHELİ
# sonuçlarda eczacı için bilgi notu olarak rapora yazılır.
