def _statin_ldl_kelimesizler_bul(metin: str) -> List[Dict]:
    """Statin bağlamı fallback: 'LDL' kelimesi yok, sadece tarih + değer + MG/DL.

    Örnek: '29.04.2024:149 MG/DL' (AHMET YEŞİLBUDAK).
    Statin raporlarında bazı eski yazımlarda LDL etiketi yok; tek satırdaki
    'TARIH:NNN MG/DL' formatı muhtemelen LDL ölçümüdür. MG/DL zorunlu —
    yanlış pozitifleri (kan şekeri, A1c vb.) ele.
    """
    if not metin:
        return []
    metin = re.sub(
        r'\(?\s*ekleme\s*[=:]\s*\d{1,2}[./\-]\d{1,2}[./\-]\d{2,4}'
        r'(?:\s+\d{1,2}:\d{2}(?::\d{2})?)?\)?',
        ' ', metin, flags=re.IGNORECASE,
    )
    olcumler: List[Dict] = []
    pat = re.compile(
        r'(?<![/.\d\-])(\d{1,2})[./\-](\d{1,2})[./\-](\d{2,4})'
        r'\s*[:=]?\s*(\d{2,3})(?![./\d\-])\s*mg\s*/?\s*dl',
        re.IGNORECASE,
    )
    # LDL OLMAYAN ölçüm adları — bunlardan biri yakındaki önceki bağlamda
    # geçiyorsa eşleşmeyi reddet (kan şekeri, A1c, HDL, trigliserit vb.).
    NEGATIF_BAGLAMLAR = (
        'kan sekeri', 'kan şekeri', 'aclik', 'açlık', 'glikoz', 'glucose',
        'hba1c', 'a1c', 'hbalc',
        'hdl', 'kolesterol toplam', 'total kolesterol', 'totalkol',
        'trigliser', 'trigiliser', 'triglyceri',
        'kreatinin', 'tsh', 'üre', 'ure ', 'na+', 'k+', 'sodyum', 'potasyum',
    )
    from datetime import date as _date
    for m in pat.finditer(metin):
        try:
            deg = int(m.group(4))
        except ValueError:
            continue
        if not (10 <= deg <= 600):
            continue
        # Önceki 50 karakterde başka bir ölçüm adı varsa eşleşmeyi reddet.
        onceki = (metin[max(0, m.start() - 50):m.start()]
                  .replace('İ', 'i').replace('I', 'ı').lower())
        if any(k in onceki for k in NEGATIF_BAGLAMLAR):
            continue
        try:
            g, a, y = int(m.group(1)), int(m.group(2)), int(m.group(3))
            if y < 100:
                y = 2000 + y if y < 50 else 1900 + y
            if not (1 <= g <= 31 and 1 <= a <= 12 and 2015 <= y <= 2100):
                continue
            tarih_obj = _date(y, a, g)
        except (ValueError, OverflowError):
            continue
        bas = max(0, m.start() - 60)
        son = min(len(metin), m.end() + 60)
        olcumler.append({
            'deger': deg,
            'pos': m.start(4),
            'tarih': tarih_obj,
            'cevre': metin[bas:son].strip(),
        })
    return olcumler


def _statin_atom_ldl_olcumler(metin: str) -> Tuple[Optional[int], List[Dict]]:
    """LDL ölçümlerini metinden çek.

    Önce standart parser (LDL prefix'li yazımlar). Hiç bulunamazsa statin
    bağlamı fallback: 'TARIH:NNN MG/DL' formatı LDL kabul edilir.
    """
    olcumler = _tum_ldl_olcumlerini_bul(metin)
    if not olcumler:
        olcumler = _statin_ldl_kelimesizler_bul(metin)
    if not olcumler:
        return None, []
    return max(o['deger'] for o in olcumler), olcumler


def _statin_olcum_durum_cevir(durum_str: str) -> SartDurumu:
    """_iki_olcum_kuralini_dogrula durumundan SartDurumu üret."""
    if durum_str == 'uygun':
        return SartDurumu.VAR
    if durum_str in ('tarih_yok', 'esik_alti'):
        return SartDurumu.KONTROL_EDILEMEDI
    return SartDurumu.YOK


def _statin_olcum_atomu(olcumler: List[Dict], esik: int,
                          rapor_tipi: str, devam_ibare: str
                          ) -> Tuple[SartDurumu, str]:
    """2 ölçüm + 1 hafta atomu — devam raporunda mevzuat gereği aranmaz.

    SUT 4.2.28.A-1 madde (3) son cümle: 'Raporun yenilenmesinde lipid düzeyini
    gösteren yeni bir tetkik sonucu istenmez.' → DEVAM ise atom VAR (bilgi).
    """
    if rapor_tipi == 'DEVAM':
        return (SartDurumu.VAR,
                f'Devam raporu ("{devam_ibare}") — '
                f'tetkik aranmaz (madde 3 son cümle)')
    ko = _iki_olcum_kuralini_dogrula(olcumler, esik=esik)
    return _statin_olcum_durum_cevir(ko['durum']), ko['detay']


def _statin_atom_ht(metin_lower: str, teshis_metin: str) -> bool:
    """SUT 4.2.28.A(2)(a) — Hipertansiyon."""
    if any(k in teshis_metin for k in ['I10', 'I11', 'I12', 'I13', 'I15']):
        return True
    return bool(re.search(
        r'\bhipertansiyon|\bht\b|yüksek\s*tansiyon|kan\s*basınc.{0,20}yüksek',
        metin_lower))


def _statin_atom_aile_erken_kv(metin_lower: str) -> bool:
    """SUT 4.2.28.A(2)(b) — Ailede erken kardiyovasküler hastalık öyküsü."""
    patterns = [
        r'aile.{0,40}erken\s*(?:kv|kvh|kardiyovask|koroner)',
        r'erken\s*kardiyovask.{0,40}aile',
        r'ailede.{0,40}erken\s*(?:mi|miyokard|kah|inme|stroke)',
        r'aile\s*öyküs.{0,30}(?:erken|kv|kah|mi)',
        r'\bailesel\s*hiperkol',
    ]
    return any(re.search(p, metin_lower) for p in patterns)


def _statin_atom_yas_65(yas: Optional[int]) -> SartDurumu:
    """SUT 4.2.28.A(2)(c) — 65 yaş ve üstü."""
    if yas is None:
        return SartDurumu.KONTROL_EDILEMEDI
    return SartDurumu.VAR if yas >= 65 else SartDurumu.YOK


def _kv_kaynak_siki_mi(kaynak: str) -> bool:
    """KV/risk atomu kaynağı 'sıkı kanıt' mı? (REFİKA kuralı — 2026-05-22)

    SUT denetiminde KV hastalık (DM/AKS/Mİ/inme/KAH/PAH/AAA/karotid)
    tespitinde kanıt hiyerarşisi:

    SIKI (True — VAR sayılır):
      • aktif_teshis*  — reçete satırı/rapor teşhis ICD'si (somut)
      • gecmis_icd:*   — hastanın geçmiş raporlarındaki ICD listesi (resmi)
      • gecmis_rapor:* — geçmiş resmi rapor metni (tarihli/imzalı belge)
      • rapor_kodu:*   — rec_rap_kod otoritesi (örn KAH için 04.02/04.04)
      • aktif_metin:antidiyabetik* — ilaç tedavisi (DM için objektif)
      • aktif_metin:HbA1c=*  — WHO/ADA DM tanı kriteri (lab)
      • aktif_metin:AKŞ=*    — WHO/ADA DM tanı kriteri (lab)

    ZAYIF (False — KE sayılır, manuel doğrulama gerekli):
      • aktif_metin (sade) — doktorun aktif rapora yazdığı serbest ibare;
        hastanın resmi ek hastalık raporu olmadan ifade tek başına yeterli
        değil (REFİKA SARIGÜL 2R8W2UK).
      • '' (boş) — hiç kaynak yok

    Kullanıcı kuralı: "Eğer hastanın diyabet/KAH/AAA/SVH/periferik damar
    hastalığı gibi ek hastalık RAPORU yok ise sadece reete/rapor metninde
    ibare geçmesini ŞÜPHELİ olarak ele alalım".
    """
    if not kaynak:
        return False
    if kaynak == 'aktif_metin':
        return False  # ZAYIF: doktor serbest beyan, somut belge yok
    # Kategorize edilmiş tüm kaynaklar (aktif_metin:lab, aktif_teshis:*,
    # gecmis_*, rapor_kodu:*) — sıkı kanıt
    return True


def _lipid_gecmis_icd_var(diger_icd: Optional[List[str]],
                             icd_prefixleri: Tuple[str, ...]
                             ) -> Tuple[bool, str]:
    """Hastanın geçmiş raporlarındaki ICD listesinde verilen prefix'lerden
    biri var mı? (Bkz. YOAK kalıbı `_yoak_gecmis_icd_var`.)

    Jenerik helper — statin (4.2.28.A) + fibrat (4.2.28.B) atomları
    tarafından paylaşılır. 2026-05-16'da `_statin_gecmis_icd_var`'dan
    rename edildi (FERİDE EGE fibrat geçmiş rapor desteği eklendiğinde).

    Format: ['I25.9 KAH', 'I63.0 İskemik inme', '[Rap 04.02] KAH']
    Returns: (var_mi, eşleşen_satir)
    """
    if not diger_icd:
        return (False, '')
    for satir in diger_icd:
        if not satir:
            continue
        satir_upper = satir.upper()
        for pre in icd_prefixleri:
            pu = pre.upper()
            if satir_upper.startswith(pu) or f' {pu}' in satir_upper:
                return (True, satir)
    return (False, '')


def _lipid_gecmis_metin_ara(diger_rapor_metinleri: Optional[List[str]],
                              pattern: str,
                              *,
                              aile_oykusu_redder: bool = False
                              ) -> Tuple[bool, str]:
    """Hastanın geçmiş rapor metinlerinde verilen regex'i ara.

    Jenerik helper — statin (4.2.28.A) + fibrat (4.2.28.B) atomları
    tarafından paylaşılır. KV/sekonder koruma şartları (KAH/MI/inme/AKS/
    PAH/AAA/karotid) hastanın geçmiş raporlarında metinsel kanıt olarak da
    kabul edilir — örn: "KAG yapıldı", "stent uygulandı", "geçirilmiş MI".
    Aktif rapor metnindeki kanıt + geçmiş rapor ICD'leri yetersiz kaldığında
    fallback. 2026-05-16'da `_statin_gecmis_metin_ara`'dan rename edildi.

    Args:
        diger_rapor_metinleri: reçete tarihinden ÖNCEKİ tüm rapor açıklamaları.
        pattern: regex (IGNORECASE çalıştırılır).
        aile_oykusu_redder: True ise eşleşmenin öncesindeki 40 karakterde
            'aile/ailesel/öykü/oyku' geçiyorsa REDDET (KAH/MI/inme gibi hastanın
            kendisinde olması gereken şartlar için — aile öyküsü hasta'da
            hastalık değildir).

    Returns: (var_mi, eşleşen_kısa_parça)
    """
    if not diger_rapor_metinleri:
        return (False, '')
    pat = re.compile(pattern, re.IGNORECASE)
    for rm in diger_rapor_metinleri:
        if not rm:
            continue
        rm_lower = rm.replace('İ', 'i').replace('I', 'ı').lower()
        for m in pat.finditer(rm_lower):
            if aile_oykusu_redder:
                on40 = rm_lower[max(0, m.start() - 40):m.start()]
                if any(k in on40 for k in
                       ('aile', 'ailesel', 'öykü', 'oyku')):
                    continue
            bas = max(0, m.start() - 30)
            son = min(len(rm), m.end() + 30)
            parca = rm[bas:son].strip().replace('\n', ' ').replace('\r', ' ')
            return (True, f'gecmis_rapor: ...{parca}...')
    return (False, '')


def _statin_atom_dm(metin_lower: str, teshis_metin: str,
                    diger_icd: Optional[List[str]] = None
                    ) -> Tuple[bool, str]:
    """SUT 4.2.28.A(1)(ç) — Diabetes mellitus.

    Returns: (var_mi, kaynak) — kaynak: 'aktif_metin' | 'aktif_teshis' |
                                          'gecmis_icd:<satir>' | ''

    Kanıt kaynakları (öncelik sırası):
      1. Aktif teşhis ICD (E10-E14)
      2. Aktif rapor metni: lafzen "diyabet/DM/şeker hastalığı"
      3. Aktif rapor metni: antidiyabetik ilaç adı (metformin/sulfonilürel/
         insülin/DPP4/SGLT2/GLP1/glitazon) — hasta DM tedavisi alıyor
      4. Aktif rapor metni: HbA1c ≥ 6.5% (WHO/ADA DM tanı kriteri)
      5. Aktif rapor metni: Açlık Kan Şekeri ≥ 126 mg/dL (WHO/ADA tanı)
      6. Geçmiş raporların ICD'leri (E10-E14)

    FADİM YÜKSEL 3NC6FI8 (2026-05-22): "Metformin ve Sulfonilureleri" +
    "Hemoglobin A1c: 9.9" + "Açlık Kan Şekeri: 147" — hepsi DM kanıtı.
    """
    if any(k in teshis_metin for k in ['E10', 'E11', 'E12', 'E13', 'E14']):
        return (True, 'aktif_teshis')
    # Antidiyabetik ilaç adları → hasta DM tedavisi alıyor (lafzen DM ima)
    ilac_pattern = (
        r'\bmetformin\w*|\bsulfonil[uüy]re\w*|\binsul[iı]n\w*|\binsülin\w*|'
        r'\bgliklazid\w*|\bglimepirid\w*|\bglibenklamid\w*|\bpiyoglitazon\w*|'
        r'\brepaglinid\w*|\bnateglinid\w*|'
        r'\bsitagliptin\w*|\bsaksagliptin\w*|\bvildagliptin\w*|\blinagliptin\w*|'
        r'\bempagliflozin\w*|\bdapagliflozin\w*|\bkanagliflozin\w*|'
        r'\bliraglutid\w*|\bsemaglutid\w*|\bdulaglutid\w*'
    )
    m_ilac = re.search(ilac_pattern, metin_lower)
    if m_ilac:
        return (True, f'aktif_metin:antidiyabetik({m_ilac.group(0)})')
    # HbA1c ≥ 6.5 → WHO/ADA DM tanı kriteri
    m_hba1c = re.search(
        r'(?:hb\s*a1c|hemoglobin\s*a1c|glikoz[iı]l[iı]\s*hemoglobin)\s*'
        r'[:=]?\s*(\d+(?:[.,]\d+)?)', metin_lower)
    if m_hba1c:
        try:
            val = float(m_hba1c.group(1).replace(',', '.'))
            if val >= 6.5:
                return (True, f'aktif_metin:HbA1c={val}')
        except ValueError:
            pass
    # Açlık Kan Şekeri ≥ 126 mg/dL → WHO/ADA DM tanı kriteri
    # "Açlık Kan Şekeri: 147" / "AKŞ: 147" / "FPG 147" — değer yakala
    m_aks = re.search(
        r'(?:açlık\s*kan\s*şeker[a-zçğıöşü]*|\bakş\b|'
        r'açlık\s*plazma\s*gliko[a-zçğıöşü]*|\bfpg\b)\s*'
        r'[:=]?\s*(\d{2,3})(?!\d)', metin_lower)
    if m_aks:
        try:
            val = int(m_aks.group(1))
            if val >= 126:
                return (True, f'aktif_metin:AKŞ={val}')
        except ValueError:
            pass
    gv, gs = _lipid_gecmis_icd_var(
        diger_icd, ('E10', 'E11', 'E12', 'E13', 'E14'))
    if gv:
        return (True, f'gecmis_icd:{gs}')
    # ZAYIF: aktif rapor serbest metninde 'diyabet/DM/şeker hast.' (somut
    # ICD/lab/ilaç yok) — strict kaynaklardan SONRA değerlendirilir, ki
    # geçmiş raporun E11 ICD'si "aktif_metin (zayıf)" tarafından gölgelenmesin.
    patterns = [r'\bdiyabet', r'\bdiabet', r'\bdm\b', r'\bt[12]dm\b',
                r'\bniddm\b', r'\biddm\b',
                r'tip\s*[12]\s*(?:dm|diyabet|diabet)',
                r'şeker\s*hastal', r'seker\s*hastal']
    if any(re.search(p, metin_lower) for p in patterns):
        return (True, 'aktif_metin')
    return (False, '')


def _statin_atom_aks(metin_lower: str, teshis_metin: str,
                     diger_icd: Optional[List[str]] = None,
                     diger_rapor_metinleri: Optional[List[str]] = None,
                     ) -> Tuple[bool, str]:
    """SUT 4.2.28.A(1)(ç) — Akut koroner sendrom."""
    if any(k in teshis_metin for k in ['I20', 'I21', 'I22', 'I23', 'I24']):
        return (True, 'aktif_teshis')
    # SIKI kaynaklar önce (gecmis_icd/gecmis_metin), zayıf aktif_metin sonra.
    gv, gs = _lipid_gecmis_icd_var(
        diger_icd, ('I20', 'I21', 'I22', 'I23', 'I24'))
    if gv:
        return (True, f'gecmis_icd:{gs}')
    gv2, gs2 = _lipid_gecmis_metin_ara(
        diger_rapor_metinleri,
        r'akut\s*koroner|\baks\b',
        aile_oykusu_redder=True,
    )
    if gv2:
        return (True, gs2)
    if re.search(r'akut\s*koroner|\baks\b', metin_lower):
        return (True, 'aktif_metin')
    return (False, '')


def _statin_atom_mi(metin_lower: str, teshis_metin: str,
                    diger_icd: Optional[List[str]] = None,
                    diger_rapor_metinleri: Optional[List[str]] = None,
                    ) -> Tuple[bool, str]:
    """SUT 4.2.28.A(1)(ç) — Geçirilmiş Mİ."""
    if any(k in teshis_metin for k in ['I21', 'I22', 'I25.2']):
        return (True, 'aktif_teshis')
    # Türkçe ı/i varyantları: metin_lower transformasyonu I→ı çevirir,
    # bu yüzden "STEMI" → "stemı", "NSTEMI" → "nstemı", "MIyokard" → "mıyokard"
    # olur. Hem "i" hem "ı" varyantlarını kapsa. Bonus: "enfaktusu" gibi yaygın
    # halk yazımı için "enfa(kt|rk)" eklendi (RECEP ERTEN 2RQ85MG, 2026-05-22).
    # SIKI kaynaklar önce (gecmis_icd/gecmis_metin), zayıf aktif_metin sonra.
    gv, gs = _lipid_gecmis_icd_var(diger_icd, ('I21', 'I22', 'I25.2'))
    if gv:
        return (True, f'gecmis_icd:{gs}')
    gv2, gs2 = _lipid_gecmis_metin_ara(
        diger_rapor_metinleri,
        r'm[iı]yokard\s*[iı]nfar|m[iı]yokard\s*enfa(?:rk|kt)|'
        r'geçirilmiş\s*m[iı]\b|\bstem[iı]\b|\bnstem[iı]\b',
        aile_oykusu_redder=True,
    )
    if gv2:
        return (True, gs2)
    if re.search(
        r'm[iı]yokard\s*[iı]nfar|m[iı]yokard\s*enfa(?:rk|kt)|'
        r'geçirilmiş\s*m[iı]\b|\bstem[iı]\b|\bnstem[iı]\b',
            metin_lower):
        return (True, 'aktif_metin')
    return (False, '')


def _statin_atom_inme(metin_lower: str, teshis_metin: str,
                      diger_icd: Optional[List[str]] = None,
                      diger_rapor_metinleri: Optional[List[str]] = None,
                      ) -> Tuple[bool, str]:
    """SUT 4.2.28.A(1)(ç) — Geçirilmiş inme."""
    if any(k in teshis_metin for k in
           ['I60', 'I61', 'I62', 'I63', 'I64', 'I65', 'I66', 'I69']):
        return (True, 'aktif_teshis')
    # SIKI kaynaklar önce (gecmis_icd/gecmis_metin), zayıf aktif_metin sonra.
    gv, gs = _lipid_gecmis_icd_var(
        diger_icd, ('I60', 'I61', 'I62', 'I63', 'I64', 'I65', 'I66', 'I69'))
    if gv:
        return (True, f'gecmis_icd:{gs}')
    gv2, gs2 = _lipid_gecmis_metin_ara(
        diger_rapor_metinleri,
        r'\binme\b|\bstroke\b|serebrovask|\bsvo\b|geçirilmiş\s*inme',
        aile_oykusu_redder=True,
    )
    if gv2:
        return (True, gs2)
    if re.search(
        r'\binme\b|\bstroke\b|serebrovask|\bsvo\b|geçirilmiş\s*inme',
            metin_lower):
        return (True, 'aktif_metin')
    return (False, '')


def _statin_atom_kah(metin_lower: str, teshis_metin: str,
                     rapor_kodu: str,
                     diger_icd: Optional[List[str]] = None,
                     diger_rapor_metinleri: Optional[List[str]] = None,
                     ) -> Tuple[bool, str]:
    """SUT 4.2.28.A(1)(ç) — Koroner arter hastalığı (hastanın kendisinde).

    rapor_kodu 04.02 / 04.04 KAH örtük endikasyon (rec_rap_kod otoritesi).
    'ailede/aile öyküsünde koroner arter' → hasta'da KAH değil, aile öyküsü.

    Kaynaklar (öncelik sırası):
      1) aktif rapor kodu (04.02/04.04)
      2) aktif reçete teşhisleri (ICD I20-25)
      3) aktif rapor metni (koroner arter / KAH / stent / bypass / iskemik kalp)
      4) geçmiş raporların ICD'leri (diger_icd)
      5) geçmiş raporların METİNLERİ (diger_rapor_metinleri) — KAG/anjio dahil
    """
    rk = (rapor_kodu or '').strip()
    if rk.startswith(('04.02', '04.04')):
        return (True, f'aktif_teshis:rap_kod {rk}')
    if any(k in teshis_metin for k in
           ['I20', 'I21', 'I22', 'I23', 'I24', 'I25']):
        return (True, 'aktif_teshis')
    # ── SIKI KAYNAKLAR ÖNCE (REFİKA kuralı, MEHMET ÖZDEMİR 3NPN3NN
    # 2026-06-03): Geçmiş/bağlı raporun ICD'si (I20-25) sıkı kanıttır ve
    # zayıf "aktif rapor serbest metni" kontrolünden ÖNCE değerlendirilmeli.
    # Aksi halde rapor metninde "koroner arter" lafzı geçtiğinde atom strict
    # ICD'ye (I25.0) hiç bakmadan aktif_metin (zayıf) dönüp ŞÜPHELİ üretiyordu.
    gv, gs = _lipid_gecmis_icd_var(
        diger_icd, ('I20', 'I21', 'I22', 'I23', 'I24', 'I25'))
    if gv:
        return (True, f'gecmis_icd:{gs}')
    # Geçmiş rapor metinleri — KAG/anjiyo dahil sekonder koruma kanıtları
    gv2, gs2 = _lipid_gecmis_metin_ara(
        diger_rapor_metinleri,
        r'\bkah\b|koroner\s*arter|iskemik\s*kalp|\bkabg\b|by[-\s]?pass|'
        r'\bstent\b|\bkag\b|anjio(?:graf|plast)',
        aile_oykusu_redder=True,
    )
    if gv2:
        return (True, gs2)
    # ── ZAYIF: aktif rapor serbest metni (somut ICD/belge yok) ──
    # 'koroner arter' her oluşumunu kontrol et — öncesinde aile/öykü/ailesel
    # varsa AKIL hastanın kendisinde değil
    for m in re.finditer(r'koroner\s*arter', metin_lower):
        on40 = metin_lower[max(0, m.start() - 40):m.start()]
        if any(k in on40 for k in ('aile', 'ailesel', 'öykü', 'oyku')):
            continue
        return (True, 'aktif_metin')
    # KAH/iskemik kalp/stent/bypass/KAG/anjiyo — bunlar hasta'da var demek.
    # anjiyo varyantları: anjio, anjıo, anjiyo, anjıyo + opsiyonel graf/plast
    # suffix. "anjiyo uygulandı" da kapsanır (YAĞMUR DOĞAN 3M5HM7G, 2026-05-22).
    if re.search(
            r'\bkah\b|iskemik\s*kalp|\bkabg\b|by[-\s]?pass|\bstent\b|'
            r'\bkag\b|anj[iı]y?o(?:graf|plast)?',
            metin_lower):
        return (True, 'aktif_metin')
    return (False, '')


def _statin_atom_pah(metin_lower: str, teshis_metin: str,
                     diger_icd: Optional[List[str]] = None,
                     diger_rapor_metinleri: Optional[List[str]] = None,
                     ) -> Tuple[bool, str]:
    """SUT 4.2.28.A(1)(ç) — Periferik arter hastalığı."""
    if any(k in teshis_metin for k in ['I70', 'I73', 'I74']):
        return (True, 'aktif_teshis')
    # SIKI kaynaklar önce (gecmis_icd/gecmis_metin), zayıf aktif_metin sonra.
    gv, gs = _lipid_gecmis_icd_var(diger_icd, ('I70', 'I73', 'I74'))
    if gv:
        return (True, f'gecmis_icd:{gs}')
    gv2, gs2 = _lipid_gecmis_metin_ara(
        diger_rapor_metinleri,
        r'periferik\s*arter|\bpah\b|\bpaod\b',
        aile_oykusu_redder=True,
    )
    if gv2:
        return (True, gs2)
    if re.search(r'periferik\s*arter|\bpah\b|\bpaod\b', metin_lower):
        return (True, 'aktif_metin')
    return (False, '')


