def _yoak_yas_oku(ilac_sonuc: Dict, metin: str = '') -> Optional[int]:
    """ilac_sonuc.hasta_yasi → int veya metinden yaş kalıbı parse.

    `_osteo_yas_oku` ile aynı mantık (4.2.17 modülünde test edilmiş).
    """
