# Ranolazin (SUT 4.2.15.F) — Çeşitli menüsüne eklendi 2026-05-13.
# Kronik stabil angina pektoris + BB/KKB yetersiz/intolerans, kardiyoloji
# 2 yıl uzman raporu, kardiyo veya iç hast. reçete.
_CESITLI_RANOLAZIN_ETKEN = ('RANOLAZIN', 'RANOLAZINE')
_CESITLI_RANOLAZIN_TICARI = ('RANEXA',)

# Hemanjiyom — Propranolol HCl oral çözelti (SUT 4.2.62).
# 2026-05-23: HEMANGIOL marka adı ve "oral çözelti" form ibaresi ile tespit.
# Tablet propranolol antihipertansif olarak kalır; sadece oral çözelti formu
# bebek hemanjiyomu (5 hafta - 5 ay) endikasyonuna yönelir.
_CESITLI_HEMANJIYOM_TICARI = ('HEMANGIOL',)
_CESITLI_HEMANJIYOM_FORM_IBARELERI = (
    'ORAL ÇÖZELTI', 'ORAL COZELTI', 'ORAL CÖZELTI', 'ORAL ÇOZELTI',
    'ORAL SOLUSYON', 'ORAL SOLÜSYON', 'ORAL SOLUTION',
    'OR. COZELTI', 'OR.COZELTI', 'OR. ÇÖZELTI',
)


def _cesitli_hemanjiyom_eslesti_mi(ilac_adi: str, etkin_madde: str) -> bool:
    """HEMANGIOL (propranolol oral çözelti — SUT 4.2.62) tespiti.

    İki yoldan biri yeterli:
      1) İlaç adında 'HEMANGIOL' marka geçer (en güvenilir).
      2) İlaç adı 'PROPRANOLOL' ve form ibaresi 'ORAL ÇÖZELTI/SOLÜSYON' var
         (ileride başka jenerik propranolol oral çözeltiler çıkarsa diye).

    Tablet/IV/diğer formlardaki propranolol antihipertansif kapsamında kalır.
    """
    ad = (ilac_adi or '').upper()
    et = (etkin_madde or '').upper()
    if any(t in ad for t in _CESITLI_HEMANJIYOM_TICARI):
        return True
    if 'PROPRANOLOL' in (ad + ' ' + et):
        if any(f in ad for f in _CESITLI_HEMANJIYOM_FORM_IBARELERI):
            return True
    return False


def _cesitli_alt_grup_tespit(ilac_adi: str, etkin_madde: str,
                              atc_kodu: str) -> str:
    """Satırın ÇEŞİTLİ kapsamına girip girmediğini ve hangi alt gruba ait
    olduğunu tespit eder.

    Dönüş: 'URINER' / 'GOZYASI' / 'BPH' / 'RANOLAZIN' / 'HEMANJIYOM' /
           'ALPROSTADIL' / 'APREPITANT' / 'NONE'

    ATC önceliği:
      - G04BD*  → URINER (üriner antispazmotik / Mirabegron)
      - G04BE*  → ALPROSTADIL (EK-4/F 37.1 — erektil disfonksiyon)
      - A04AD12 + APREPITANT/EMEND (fosaprepitant hariç) → APREPITANT (EK-4)
      - G04CA*  → BPH (α-bloker — BPH'da kullanılan)
      - S01E*   → GLOKOM (SUT 4.2.11 — antiglokom)
      - S01XA / S01KA / S01X  → GOZYASI (oftalmoloji)
      - N06AX21 → URINER (Duloksetin — üriner endikasyonu için)
      - C01EB18 → RANOLAZIN (SUT 4.2.15.F — kronik stabil angina)
      - C07AA05 + oral çözelti / HEMANGIOL → HEMANJIYOM (SUT 4.2.62)
    """
    ad = (ilac_adi or '').upper()
    et = (etkin_madde or '').upper()
    a = (atc_kodu or '').upper().strip()

    # HEMANJIYOM önce: propranolol oral çözelti antihipertansiften ayrılır.
    if _cesitli_hemanjiyom_eslesti_mi(ad, et):
        return 'HEMANJIYOM'

    # ALPROSTADIL (EK-4/F 37.1 — erektil disfonksiyon, ürolojik 10/20 mcg/ml)
    if a.startswith('G04BE'):
        return 'ALPROSTADIL'
    if 'ALPROSTADIL' in (ad + ' ' + et) or any(
            t in ad for t in ('CAVERJECT', 'KAVERJECT', 'VITAROS', 'VIRIDAL', 'MUSE')):
        return 'ALPROSTADIL'

    # APREPITANT (EK-4 — KT ilişkili bulantı/kusma; EMEND oral).
    # Fosaprepitant (IVEMEND) AYNI ATC'yi paylaşır → ad ile ayrılır.
    arama_ap = ad + ' ' + et
    if 'FOSAPREPITANT' not in arama_ap and 'IVEMEND' not in arama_ap:
        if 'APREPITANT' in arama_ap or 'EMEND' in ad:
            return 'APREPITANT'

    # ATOMOKSETIN (DEHB — N06BA09; yalnız atomoksetin, metilfenidat hariç)
    if a.startswith('N06BA09'):
        return 'ATOMOKSETIN'
    if 'ATOMOKSETIN' in arama_ap or 'ATOMOXETIN' in arama_ap or any(
            t in ad for t in ('STRATTERA', 'ATOMINEX', 'ATTENTROL', 'ATOMERA')):
        return 'ATOMOKSETIN'

    # DESMOPRESSIN (H01BA02 — enürezis nokturna / santral DI, raporsuz a şıkkı)
    if a.startswith('H01BA02'):
        return 'DESMOPRESSIN'
    if 'DESMOPRESSIN' in arama_ap or 'DESMOPRESIN' in arama_ap or any(
            t in ad for t in ('MINIRIN', 'MINIMELT', 'NOCDURNA', 'NOQDIRNA',
                              'OCTOSTIM', 'DESMOSPRAY', 'DESMOMELT')):
        return 'DESMOPRESSIN'

    # DEMANS/ALS (EK-4/F m.7 — donepezil/galantamin/memantin/rivastigmin/riluzol)
    if a.startswith('N06DA') or a.startswith('N06DX01') or a.startswith('N07XX02'):
        return 'DEMANS_ALS'
    if any(e in arama_ap for e in ('DONEPEZIL', 'GALANTAMIN', 'MEMANTIN',
                                   'RIVASTIGMIN', 'RILUZOL')) or any(
            t in ad for t in ('ARICEPT', 'REMINYL', 'EBIXA', 'AXURA',
                              'EXELON', 'RILUTEK')):
        return 'DEMANS_ALS'

    # FLUDROKORTIZON (EK-4/F m.77 — adrenal / otonom nöropati) — ATC H02AA02
    if a.startswith('H02AA02'):
        return 'FLUDROKORTIZON'
    if 'FLUDROKORTIZON' in arama_ap or 'FLUDROCORTISON' in arama_ap or any(
            t in ad for t in ('ASTONIN', 'FLORINEF')):
        return 'FLUDROKORTIZON'

    # LEFLUNOMID (SUT 4.2.1.A — romatoid/psoriatik artrit) — ATC L04AA13.
    # Anti-TNF (L04AB*) ile çakışmaz; konvansiyonel sentetik DMARD.
    if a.startswith('L04AA13'):
        return 'LEFLUNOMID'
    if 'LEFLUNOMID' in arama_ap or 'LEFLUNOMIDE' in arama_ap or any(
            t in ad for t in ('ARAVA', 'LEFNO', 'IMMULEF', 'REPSO', 'ARABLOCK',
                              'LEFLAR', 'LUNAVA', 'ZALEF', 'ROFLON', 'LEFLODENK')):
        return 'LEFLUNOMID'

    # IVERMEKTIN (EK-4/F — strongiloidiyaz/filariasis + insan uyuzu) — ATC P02CF01
    if a.startswith('P02CF01'):
        return 'IVERMEKTIN'
    if 'IVERMEKTIN' in arama_ap or 'IVERMECTIN' in arama_ap or any(
            t in ad for t in ('STROMECTOL', 'IVEROTOX', 'IVERZINE', 'SCABO')):
        return 'IVERMEKTIN'

    # GINKGO (EK-4/F m.55 — demans, 65 yaş+) — ATC N06DX02 (memantin N06DX01 ≠)
    if a.startswith('N06DX02'):
        return 'GINKGO'
    if 'GINKGO' in arama_ap or 'GINGKO' in arama_ap or any(
            t in ad for t in ('TEBOKAN', 'TANAKAN', 'BILOBIL', 'GINGIUM',
                              'GINKOR', 'MEMOPLANT')):
        return 'GINKGO'

    # SETRON (EK-4/F m.11 — 5-HT3 antiemetik doz limiti) — ATC A04AA01/02/03/05.
    # Aprepitant (A04AD12, NK1) buraya düşmez (A04AA ≠ A04AD).
    if a.startswith('A04AA'):
        return 'SETRON'
    if any(e in arama_ap for e in ('PALONOSETRON', 'GRANISETRON', 'ONDANSETRON',
                                   'TROPISETRON')) or any(
            t in ad for t in ('ALOXI', 'KYTRIL', 'ZOFER', 'ZOFRAN', 'EMESET',
                              'NAVOBAN', 'ONDAVELL')):
        return 'SETRON'

    # MEKLOZIN (PRİZİN — gebelik/ameliyat/röntgen sonrası bulantı) — ATC R06AE05
    if a.startswith('R06AE05') or a.startswith('R06AE55'):
        return 'MEKLOZIN'
    if 'MEKLOZIN' in arama_ap or 'MECLOZINE' in arama_ap or 'MECLIZINE' in arama_ap \
            or 'PRIZIN' in ad or 'PRİZİN' in ad:
        return 'MEKLOZIN'

    # ORLISTAT (SUT 4.2.18 — obezite) — ATC A08AB01
    if a.startswith('A08AB01'):
        return 'ORLISTAT'
    if 'ORLISTAT' in arama_ap or any(
            t in ad for t in ('XENICAL', 'ORSLIM', 'REDUMED', 'ALLI')):
        return 'ORLISTAT'

    # PENTOSAN polisülfat (EK-4/F m.69 — interstisyel sistit, üroloji) — ATC G04BX15
    if a.startswith('G04BX15'):
        return 'PENTOSAN'
    if 'PENTOSAN' in arama_ap or 'ELMIRON' in ad:
        return 'PENTOSAN'

    # PIMEKROLIMUS/TAKROLIMUS topikal (SUT 4.2.58, dermatoloji) — ATC D11AH01/02.
    # Sistemik takrolimus (L04AD02, PROGRAF) HARİÇ.
    if a.startswith('D11AH01') or a.startswith('D11AH02'):
        return 'PIMTAK'
    if not a.startswith('L04AD'):
        if 'PIMEKROLIMUS' in arama_ap or 'PIMECROLIMUS' in arama_ap \
                or 'ELIDEL' in ad or 'PROTOPIC' in ad:
            return 'PIMTAK'

    # ANTİFUNGAL (SUT 4.2.23 sistemik) — amfoterisin/kaspofungin/anidulafungin/
    # vorikonazol/posakonazol/itrakonazol/mikafungin. Flukonazol (J02AC01) HARİÇ.
    if a.startswith('J02AA01') or a.startswith('J02AX04') or a.startswith('J02AX05') \
            or a.startswith('J02AX06') or a.startswith('J02AC02') \
            or a.startswith('J02AC03') or a.startswith('J02AC04'):
        return 'ANTIFUNGAL'
    if any(e in arama_ap for e in (
            'AMFOTERISIN', 'AMPHOTERICIN', 'KASPOFUNGIN', 'ANIDULAFUNGIN',
            'ANIDILOFUNGIN', 'MIKAFUNGIN', 'MICAFUNGIN', 'VORIKONAZOL',
            'VORIKANAZOL', 'POSAKONAZOL', 'ITRAKONAZOL')) or any(
            t in ad for t in ('AMBISOME', 'ABELCET', 'CANCIDAS', 'ECALTA',
                              'MYCAMINE', 'VFEND', 'NOXAFIL', 'SPORANOX')):
        return 'ANTIFUNGAL'

    if a.startswith('G04BD'):
        return 'URINER'
    # FINASTERID/DUTASTERID (BPH 5-ARI) — G04CB* + G04CA52 (dutasterid+tamsulosin
    # = DUODART) + etken. G04CA→BPH'den ÖNCE: DUODART (G04CA52) bu gruba düşmeli.
    if a.startswith('G04CB') or a.startswith('G04CA52') \
            or 'FINASTERID' in arama_ap or 'DUTASTERID' in arama_ap or any(
                t in ad for t in ('PROSCAR', 'PROPECIA', 'AVODART', 'DUODART',
                                  'COMBODART')):
        return 'FINDUT'
    if a.startswith('G04CA'):
        return 'BPH'
    # GLOKOM (SUT 4.2.11 — antiglokom S01E*) — gözyaşı (S01XA) ile çakışmaz.
    if a.startswith('S01E'):
        return 'GLOKOM'
    if a.startswith('S01XA') or a.startswith('S01KA') or a.startswith('S01X'):
        return 'GOZYASI'
    if a.startswith('N06AX21'):
        return 'URINER'
    if a.startswith('C01EB18'):
        return 'RANOLAZIN'

    arama = ad + ' ' + et

    if (any(e in arama for e in _CESITLI_URINER_ANTIMUSKARINIK_ETKEN)
            or any(e in arama for e in _CESITLI_URINER_BETA3_ETKEN)
            or any(t in ad for t in _CESITLI_URINER_ANTIMUSKARINIK_TICARI)
            or any(t in ad for t in _CESITLI_URINER_BETA3_TICARI)):
        return 'URINER'
    if (any(e in arama for e in _CESITLI_URINER_DULOKSETIN_ETKEN)
            or any(t in ad for t in _CESITLI_URINER_DULOKSETIN_TICARI)):
        return 'URINER'
    if (any(e in arama for e in _CESITLI_GOZYASI_ETKEN)
            or any(t in ad for t in _CESITLI_GOZYASI_TICARI)):
        return 'GOZYASI'
    if (any(e in arama for e in _CESITLI_BPH_ALFA_ETKEN)
            or any(t in ad for t in _CESITLI_BPH_TICARI)):
        return 'BPH'
    if (any(e in arama for e in _CESITLI_RANOLAZIN_ETKEN)
            or any(t in ad for t in _CESITLI_RANOLAZIN_TICARI)):
        return 'RANOLAZIN'
    # GLOKOM etken/ticari fallback (ATC yoksa)
    try:
        from recete_kontrol.glokom_4_2_11 import glokom_kapsami_mi
        if glokom_kapsami_mi({'ilac_adi': ad, 'etkin_madde': et, 'atc_kodu': a}):
            return 'GLOKOM'
    except Exception:
        pass
    return 'NONE'


def _cesitli_aile_hekimi_tespit(doktor_brans: str, kurum_adi: str,
                                  tesis_kodu: str,
                                  doktor_adi: str = '') -> Tuple[bool, str]:
    """ARB ile aynı 4 yollu aile hekimi tespiti (kronik hastalık hekimi dahil).
    Dönüş: (aile_hekimi_mi, yetki_kaynagi_aciklamasi)
    """
    db = (doktor_brans or '').upper()
    ka = (kurum_adi or '').upper()
    tk = str(tesis_kodu or '').strip()

    brans_aile_hek = (
        'AILE HEK' in db or 'AİLE HEK' in db
        or 'AİLE HEKİMLİĞİ' in db or 'AILE HEKIMLIGI' in db
    )
    kurum_asm = bool(ka) and (
        'AILE SAGLIGI' in ka or 'AİLE SAĞLIĞI' in ka
        or 'AILE SAĞLIĞI' in ka or 'AİLE SAGLIGI' in ka
        or 'AILE HEKIMLIGI' in ka or 'AİLE HEKİMLİĞİ' in ka
        or any(tok in ka.split() for tok in ('ASM', 'AHM'))
    )
    tesis_aile_hek = bool(tk) and (tk in AILE_HEKIMLIGI_TESIS_KODLARI)
    khh_var, khh_etiket = _kronik_hastalik_hekimi_tespit(doktor_adi, tk)

    nedenler = []
    if brans_aile_hek:
        nedenler.append('branşta aile hekimliği')
    if kurum_asm:
        nedenler.append(f'kurum: {ka[:50]}')
    if tesis_aile_hek:
        nedenler.append(f'tesis kodu: {tk}')
    if khh_var:
        nedenler.append(khh_etiket)
    return (brans_aile_hek or kurum_asm or tesis_aile_hek or khh_var,
            ' + '.join(nedenler))


def kontrol_cesitli_madde_45_uriner(ilac_sonuc: Dict) -> KontrolRaporu:
    """SUT EK-4/F Madde 45 — Üriner inkontinans tedavisi.

    Kapsam:
      - Antimuskarinik: Solifenasin, Tolterodin-L, Trospiyum, Darifenasin,
                       Propiverin, Fesoterodin, Transdermal/Oral Oksibutinin
      - β3-agonist:    Mirabegron
      - SNRI (özel):   Duloksetin (yalnız erişkin kadın + stres SUI / mikst SUI)

    Kurallar:
      1. Antimuskarinik + Mirabegron: oral oksibutinine yanıtsız/intoleran
         hastalarda Nöroloji/FTR/Üroloji/Pediatri/Geriatri/Kadın-Doğum uzman
         hekim raporuna dayanılarak TÜM uzman hekimlerce reçete edilir.
      2. Duloksetin: erişkin kadın + stres SUI / mikst SUI'da Nöroloji/FTR/
         Üroloji/Geriatri/Kadın-Doğum uzman hekim raporu ile TÜM uzman
         hekimlerce reçete edilir (Pediatri YOK).
      3. KOMBİ YASAĞI: Antimuskarinikler (Mirabegron HARİÇ) birlikte ödenmez.
    """
    ilac_adi = (ilac_sonuc.get('ilac_adi') or '').upper()
    etkin_madde = (ilac_sonuc.get('etkin_madde') or '').upper()
    rapor_kodu = (ilac_sonuc.get('rapor_kodu') or '').strip()
    doktor_brans = (ilac_sonuc.get('doktor_uzmanligi') or '').upper()
    cinsiyet = (ilac_sonuc.get('cinsiyet') or '').upper().strip()

    diger_etkenler = ilac_sonuc.get('diger_etken_maddeler') or []
    diger_ilac_adlari = ilac_sonuc.get('diger_ilac_adlari') or []
    diger_arama = ' '.join(
        [str(x).upper() for x in (diger_etkenler + diger_ilac_adlari)])

    tum_metin = _tum_metinleri_birlesir(ilac_sonuc) or ''
    sut_kurali = 'SUT EK-4/F Madde 45 — Üriner inkontinans tedavisi'

    arama = ilac_adi + ' ' + etkin_madde
    is_antimuskarinik = (
        any(e in arama for e in _CESITLI_URINER_ANTIMUSKARINIK_ETKEN)
        or any(t in ilac_adi for t in _CESITLI_URINER_ANTIMUSKARINIK_TICARI)
    )
    is_mirabegron = (
        'MIRABEGRON' in arama
        or any(t in ilac_adi for t in _CESITLI_URINER_BETA3_TICARI)
    )
    is_duloksetin = (
        any(e in arama for e in _CESITLI_URINER_DULOKSETIN_ETKEN)
        or any(t in ilac_adi for t in _CESITLI_URINER_DULOKSETIN_TICARI)
    )

    detaylar = {
        'alt_grup': 'URINER',
        'ilac_adi': ilac_adi,
        'etkin_madde': etkin_madde,
        'rapor_kodu': rapor_kodu,
        'doktor_brans': doktor_brans,
        'cinsiyet': cinsiyet,
        'tip': ('ANTIMUSKARINIK' if is_antimuskarinik else
                'BETA3' if is_mirabegron else
                'DULOKSETIN' if is_duloksetin else 'BILINMEYEN'),
    }

    UZMAN_BRANSLAR = (
        'NOROLOJI', 'NÖROLOJI', 'NÖROLOJİ',
        'FIZIK TEDAVI', 'FİZİK TEDAVİ', 'FTR', 'FİZYOTERAPİ',
        'UROLOJI', 'ÜROLOJI', 'ÜROLOJİ',
        'PEDIATRI', 'PEDİATRİ', 'COCUK SAGLIGI', 'ÇOCUK SAĞLIĞI',
        'GERIATRI', 'GERİATRİ',
        'KADIN HASTALIKLARI', 'KADIN-DOGUM', 'KADIN DOĞUM', 'KADIN HAST',
        'JINEKOLOJI', 'JİNEKOLOJİ',
    )
    # Duloksetin için Pediatri YOK
    UZMAN_DULOKSETIN = tuple(
        b for b in UZMAN_BRANSLAR
        if 'PEDIATRI' not in b and 'PEDİATRİ' not in b
        and 'COCUK' not in b and 'ÇOCUK' not in b
    )

    is_uzman_brans = any(b in doktor_brans for b in UZMAN_BRANSLAR)

    # ── 1) Kombi yasağı: antimuskarinik + antimuskarinik (Mirabegron hariç) ──
    if is_antimuskarinik:
        kombi_eslesen = []
        for e in _CESITLI_URINER_ANTIMUSKARINIK_ETKEN:
            if e in diger_arama and e not in arama:
                kombi_eslesen.append(e)
        for t in _CESITLI_URINER_ANTIMUSKARINIK_TICARI:
            if t in diger_arama and t not in ilac_adi:
                kombi_eslesen.append(t)
        if kombi_eslesen:
            return KontrolRaporu(
                sonuc=KontrolSonucu.UYGUN_DEGIL,
                mesaj=(f'Antimuskarinik kombinasyon — aynı reçetede başka '
                       f'antimuskarinik var: {", ".join(set(kombi_eslesen))}'),
                detaylar={**detaylar, 'kombi_yasagi': True,
                          'kombi_eslesen': sorted(set(kombi_eslesen))},
                uyari=('SUT M.45: Antimuskarinikler birlikte ödenmez '
                       '(Mirabegron bu yasak DIŞINDA)'),
                sut_kurali=sut_kurali,
                aranan_ibare='Aynı reçetede başka antimuskarinik (kombi yasağı)',
            )

    # ── 2) Duloksetin özel kontrolü ──
    if is_duloksetin:
        if not rapor_kodu:
            # Raporsuz Duloksetin — depresyon/anksiyete kapsamında olabilir.
            # SUT M.45 kapsamında üriner için RAPOR ZORUNLU; raporsuz ise
            # bu buton kapsamı değil → ŞÜPHELİ (psikiyatri butonu kontrol etsin)
            return KontrolRaporu(
                sonuc=KontrolSonucu.KONTROL_EDILEMEDI,
                mesaj=('Duloksetin RAPORSUZ — büyük olasılıkla depresyon/'
                       'anksiyete endikasyonu (SUT 4.2.2). Üriner endikasyon '
                       'için M.45 rapor şart.'),
                detaylar={**detaylar, 'endikasyon': 'belirsiz'},
                uyari=('Duloksetin için PSİKİYATRİ butonu daha doğru kontrol '
                       'eder; üriner endikasyonda bu satır ŞÜPHELİ kalır'),
                sut_kurali=sut_kurali,
                aranan_ibare='Duloksetin üriner endikasyonu (rapor şart)',
            )

        ml = tum_metin.replace('İ', 'i').replace('I', 'ı').lower()
        sui_var = (
            ('stres' in ml and ('inkontinan' in ml or 'sui' in ml
                                  or 'üriner' in ml or 'uriner' in ml))
            or ('mikst' in ml and 'inkontinan' in ml)
            or ('mixed' in ml and ('incont' in ml or 'urinary' in ml))
        )
        kadin_kesin = cinsiyet in ('K', 'KADIN', 'KADİN', 'F', 'FEMALE')

        if not kadin_kesin:
            return KontrolRaporu(
                sonuc=KontrolSonucu.KONTROL_EDILEMEDI,
                mesaj=(f'Duloksetin raporlu (rap.kod {rapor_kodu}) — '
                       f'cinsiyet "{cinsiyet or "bilinmiyor"}" '
                       '(üriner endikasyon yalnız erişkin KADIN)'),
                detaylar={**detaylar, 'sui_var': sui_var},
                uyari=('Duloksetin üriner endikasyonda yalnız erişkin '
                       'KADIN + stres SUI / mikst SUI'),
                sut_kurali=sut_kurali,
                aranan_ibare='Cinsiyet=Kadın + stres üriner inkontinans',
            )

        if not sui_var:
            return KontrolRaporu(
                sonuc=KontrolSonucu.KONTROL_EDILEMEDI,
                mesaj=(f'Duloksetin raporlu (rap.kod {rapor_kodu}) — kadın '
                       'hasta ama stres SUI / mikst SUI ibaresi raporda '
                       'bulunamadı (depresyon olabilir)'),
                detaylar={**detaylar, 'sui_var': False},
                uyari='Üriner endikasyon için raporda STRES SUI / MİKST SUI olmalı',
                sut_kurali=sut_kurali,
                aranan_ibare='stres üriner inkontinans / mikst SUI',
            )

        if any(b in doktor_brans for b in UZMAN_DULOKSETIN):
            return KontrolRaporu(
                sonuc=KontrolSonucu.UYGUN,
                mesaj=(f'Duloksetin raporlu (rap.kod {rapor_kodu}) — kadın + '
                       f'stres SUI + uzman branş: {doktor_brans}'),
                detaylar=detaylar,
                sut_kurali=sut_kurali,
                aranan_ibare='Kadın + stres SUI + uzman branş',
            )
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN,
            mesaj=(f'Duloksetin raporlu (rap.kod {rapor_kodu}) — kadın + '
                   'stres SUI; uzman branşa rapor dayanağıyla yazılabilir'),
            detaylar=detaylar,
            sut_kurali=sut_kurali,
            aranan_ibare='Duloksetin SUI + rapor varlığı',
        )

    # ── 3) Antimuskarinik / Mirabegron ──
    if is_antimuskarinik or is_mirabegron:
        if not rapor_kodu:
            return KontrolRaporu(
                sonuc=KontrolSonucu.UYGUN_DEGIL,
                mesaj='Üriner inkontinans ilacı RAPORSUZ — uzman raporu zorunlu',
                detaylar=detaylar,
                uyari=('Nöroloji/FTR/Üroloji/Pediatri/Geriatri/Kadın-Doğum '
                       'uzman hekim raporu gerekli'),
                sut_kurali=sut_kurali,
                aranan_ibare='Uzman hekim raporu (zorunlu)',
            )

        if is_uzman_brans:
            return KontrolRaporu(
                sonuc=KontrolSonucu.UYGUN,
                mesaj=(f'Üriner inkontinans ilacı raporlu (rap.kod '
                       f'{rapor_kodu}) — uzman branş: {doktor_brans}'),
                detaylar=detaylar,
                sut_kurali=sut_kurali,
                aranan_ibare='Uzman branş + rapor',
            )

        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN,
            mesaj=(f'Üriner inkontinans ilacı raporlu (rap.kod {rapor_kodu})'
                   ' — uzman branş raporuna dayanılarak diğer uzman hekim '
                   'yazabilir'),
            detaylar=detaylar,
            sut_kurali=sut_kurali,
            aranan_ibare='Uzman branş raporuna dayanılarak diğer uzm hekim',
        )

    return KontrolRaporu(
        sonuc=KontrolSonucu.ATLANDI,
        mesaj='Üriner inkontinans kapsamında değil',
        detaylar=detaylar,
        sut_kurali=sut_kurali,
    )


def kontrol_cesitli_suni_gozyasi(ilac_sonuc: Dict) -> KontrolRaporu:
    """SUT EK-4/F Madde 2 — Suni gözyaşı (keratitis sicca / kuru göz).

    Kurallar:
      - Göz Hastalıkları uzm. raporsuz/raporlu → UYGUN
      - 1 yıl göz uzm. raporu + diğer uzm hekim → UYGUN
      - Aile hekimi raporsuz + ayda EN FAZLA 1 KUTU → UYGUN
      - Diğer (uzm raporsuz + aile hek değil) → UYGUN DEĞİL
      Doz (günde max 7 damla) Medula tarafından kontrol edilir.
    """
    ilac_adi = (ilac_sonuc.get('ilac_adi') or '').upper()
    etkin_madde = (ilac_sonuc.get('etkin_madde') or '').upper()
    rapor_kodu = (ilac_sonuc.get('rapor_kodu') or '').strip()
    doktor_brans = (ilac_sonuc.get('doktor_uzmanligi') or '').upper()
    kurum_adi = (ilac_sonuc.get('kurum_adi') or '').upper()
    tesis_kodu = str(ilac_sonuc.get('tesis_kodu') or '').strip()

    kutu_raw = ilac_sonuc.get('kutu_sayisi')
    if kutu_raw is None:
        kutu_raw = ilac_sonuc.get('miktar', '')
    try:
        kutu = float(str(kutu_raw).replace(',', '.')) \
            if str(kutu_raw).strip() else 0.0
    except (ValueError, TypeError):
        kutu = 0.0

    sut_kurali = 'SUT EK-4/F Madde 2 — Suni gözyaşı (keratitis sicca)'
    detaylar = {
        'alt_grup': 'GOZYASI',
        'ilac_adi': ilac_adi,
        'etkin_madde': etkin_madde,
        'rapor_kodu': rapor_kodu,
        'doktor_brans': doktor_brans,
        'kutu': kutu,
    }

    is_goz_uzmani = (
        'GOZ HAST' in doktor_brans or 'GÖZ HAST' in doktor_brans
        or 'OFTALMOLOJI' in doktor_brans or 'OFTALMOLOJİ' in doktor_brans
        or doktor_brans.startswith('GÖZ') or doktor_brans.startswith('GOZ')
    )
    doktor_adi_cesitli = (ilac_sonuc.get('doktor_adi') or '').strip()
    aile_hekimi, yetki_kaynagi = _cesitli_aile_hekimi_tespit(
        doktor_brans, kurum_adi, tesis_kodu, doktor_adi_cesitli)
    detaylar['aile_hekimi'] = aile_hekimi
    detaylar['is_goz_uzmani'] = is_goz_uzmani
    detaylar['yetki_kaynagi'] = yetki_kaynagi

    # Göz uzmanı yazmış → her durumda UYGUN
    if is_goz_uzmani:
        rap_str = f' (rap.kod {rapor_kodu})' if rapor_kodu else ' (raporsuz)'
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN,
            mesaj=f'Suni gözyaşı — Göz Hastalıkları uzmanı{rap_str}',
            detaylar=detaylar,
            sut_kurali=sut_kurali,
            aranan_ibare='Göz Hastalıkları uzmanı',
        )

    # Aile hekimi raporsuz + ≤1 kutu
    if aile_hekimi and not rapor_kodu:
        if kutu <= 1:
            kutu_str = f'{kutu:g}' if kutu else '≤1'
            return KontrolRaporu(
                sonuc=KontrolSonucu.UYGUN,
                mesaj=(f'Suni gözyaşı — aile hekimi raporsuz '
                       f'({yetki_kaynagi}) + {kutu_str} kutu '
                       '(SUT M.2: ayda 1 kutu sınırı)'),
                detaylar=detaylar,
                sut_kurali=sut_kurali,
                aranan_ibare='Aile hekimi + ayda ≤1 kutu',
                bulunan_metin=yetki_kaynagi,
            )
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN_DEGIL,
            mesaj=(f'Suni gözyaşı — aile hekimi raporsuz {kutu:g} kutu '
                   'yazmış (SUT sınırı: ayda 1 kutu)'),
            detaylar=detaylar,
            uyari=('Aile hekimi raporsuz suni gözyaşı ayda 1 kutu — '
                   'fazlası için göz uzm raporu şart'),
            sut_kurali=sut_kurali,
            aranan_ibare='Aile hekimi ≤1 kutu sınırı',
        )

    # Diğer uzm/hekim raporlu → 1 yıl göz uzm raporuna dayanır
    if rapor_kodu:
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN,
            mesaj=(f'Suni gözyaşı raporlu (rap.kod {rapor_kodu}) — '
                   '1 yıl göz uzm. raporuna dayanılarak yazılabilir '
                   '(doz max 7 damla/gün — Medula kontrol)'),
            detaylar=detaylar,
            uyari='Doz kontrolü Medula tarafından yapılır',
            sut_kurali=sut_kurali,
            aranan_ibare='1 yıl göz uzm raporu',
        )

    # Raporsuz + göz uzm değil + aile hekimi değil
    return KontrolRaporu(
        sonuc=KontrolSonucu.UYGUN_DEGIL,
        mesaj=(f'Suni gözyaşı RAPORSUZ — branş "{doktor_brans or "bilinmiyor"}"'
               ' (SUT M.2: göz uzm yazabilir / 1 yıl rapor / aile hek + 1 kutu)'),
        detaylar=detaylar,
        uyari='Göz uzm yazabilir VEYA 1 yıl göz raporu VEYA aile hek + 1 kutu',
        sut_kurali=sut_kurali,
        aranan_ibare='Göz uzm VEYA göz raporu VEYA aile hekimi',
    )


def kontrol_cesitli_bph_alfa_bloker(ilac_sonuc: Dict) -> KontrolRaporu:
    """SUT — Benign prostat hiperplazisi (BPH) α-blokerleri.

    Kapsam: Alfuzosin, Tamsulosin, Terazosin, Doksazosin, Silodosin

    Kurallar:
      - Üroloji uzm hekim → UYGUN
      - Üroloji uzm 1 yıl raporuna dayanılarak tüm hekimler → UYGUN
      - KOMBİNASYON YASAĞI: α-blokerler birlikte ödenmez
        İSTİSNA: Hipertansiyon eşlik ediyorsa kombi serbest
    """
    ilac_adi = (ilac_sonuc.get('ilac_adi') or '').upper()
    etkin_madde = (ilac_sonuc.get('etkin_madde') or '').upper()
    rapor_kodu = (ilac_sonuc.get('rapor_kodu') or '').strip()
    doktor_brans = (ilac_sonuc.get('doktor_uzmanligi') or '').upper()
    teshisler = ilac_sonuc.get('recete_teshisleri') or []
    teshis_metin = ' '.join(teshisler).upper() if teshisler else ''

    diger_etkenler = ilac_sonuc.get('diger_etken_maddeler') or []
    diger_ilac_adlari = ilac_sonuc.get('diger_ilac_adlari') or []
    diger_arama = ' '.join(
        [str(x).upper() for x in (diger_etkenler + diger_ilac_adlari)])

    tum_metin = _tum_metinleri_birlesir(ilac_sonuc) or ''
    sut_kurali = 'SUT — BPH α-blokerleri (Alfuzosin/Tamsulosin/Terazosin/Doksazosin/Silodosin)'

    detaylar = {
        'alt_grup': 'BPH',
        'ilac_adi': ilac_adi,
        'etkin_madde': etkin_madde,
        'rapor_kodu': rapor_kodu,
        'doktor_brans': doktor_brans,
    }

    is_uroloji = (
        'UROLOJI' in doktor_brans or 'ÜROLOJI' in doktor_brans
        or 'ÜROLOJİ' in doktor_brans
    )
    detaylar['is_uroloji'] = is_uroloji

    # ── Hipertansiyon eşlik kontrolü (ICD I10-I15 veya teşhis metni) ──
    ml = (tum_metin + ' ' + teshis_metin).replace('İ', 'i').replace('I', 'ı').lower()
    ht_var = (
        'hipertans' in ml or 'hypertan' in ml
        or any(t in teshis_metin for t in ('I10', 'I11', 'I12', 'I13', 'I14', 'I15'))
    )
    detaylar['ht_var'] = ht_var

    # ── Kombi yasağı kontrolü (HT istisnası) ──
    arama = ilac_adi + ' ' + etkin_madde
    kombi_eslesen = []
    for e in _CESITLI_BPH_ALFA_ETKEN:
        if e in diger_arama and e not in arama:
            kombi_eslesen.append(e)
    for t in _CESITLI_BPH_TICARI:
        if t in diger_arama and t not in ilac_adi:
            kombi_eslesen.append(t)

    if kombi_eslesen and not ht_var:
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN_DEGIL,
            mesaj=(f'BPH α-bloker kombinasyon — aynı reçetede başka α-bloker: '
                   f'{", ".join(set(kombi_eslesen))} (HT eşlik etmiyor)'),
            detaylar={**detaylar, 'kombi_yasagi': True,
                      'kombi_eslesen': sorted(set(kombi_eslesen))},
            uyari=('SUT: BPH α-blokerleri birlikte ödenmez. İstisna: '
                   'Hipertansiyon eşlik ediyorsa kombi serbest.'),
            sut_kurali=sut_kurali,
            aranan_ibare='Hipertansiyon teşhisi (kombi istisnası)',
        )

    if kombi_eslesen and ht_var:
        # HT eşlik → kombi serbest, normal akışa devam
        detaylar['kombi_ht_istisna'] = True

    # ── Karar ──
    if is_uroloji:
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN,
            mesaj=(f'BPH α-bloker — Üroloji uzm hekim '
                   f'(rap.kod {rapor_kodu or "yok"})'
                   + (' [HT eşlik — kombi serbest]' if (kombi_eslesen and ht_var)
                      else '')),
            detaylar=detaylar,
            sut_kurali=sut_kurali,
            aranan_ibare='Üroloji uzmanı',
        )

    if rapor_kodu:
        return KontrolRaporu(
            sonuc=KontrolSonucu.UYGUN,
            mesaj=(f'BPH α-bloker raporlu (rap.kod {rapor_kodu}) — '
                   'üroloji uzm raporuna dayanılarak tüm hekimler yazabilir'
                   + (' [HT eşlik]' if (kombi_eslesen and ht_var) else '')),
            detaylar=detaylar,
            sut_kurali=sut_kurali,
            aranan_ibare='Üroloji 1 yıl raporu',
        )

    # Raporsuz + üroloji değil → şüpheli (Medula şart kontrolü yapar)
    return KontrolRaporu(
        sonuc=KontrolSonucu.KONTROL_EDILEMEDI,
        mesaj=(f'BPH α-bloker raporsuz — branş "{doktor_brans or "bilinmiyor"}" '
               '(üroloji değil, rapor yok)'),
        detaylar=detaylar,
        uyari=('SUT: BPH α-blokerleri için Üroloji uzm hekim VEYA '
               'üroloji 1 yıl raporu gerekli'),
        sut_kurali=sut_kurali,
        aranan_ibare='Üroloji uzmanı VEYA üroloji raporu',
    )


# ═══════════════════════════════════════════════════════════════════════
# HEMANJIYOM — SUT 4.2.62 Propranolol HCl Oral Çözelti (HEMANGIOL)
# ═══════════════════════════════════════════════════════════════════════
# SUT 4.2.62 (Ek:RG-16/6/2020-31157 Mükerrer) — bebek hemanjiyomu tedavisi.
#
# Atomik şartlar (devre şeması):
#   A1+A2: yaş aralığı 5 hafta - 5 ay (AND, tek atom — gün hesabı)
#   A3:    sistemik tedavi gerektiren / morbidite hemanjiyomu (rapor metni)
#   A4:    alt madde (a) hayat tehdidi VEYA (b) ülsere VEYA (c) yara izi (≥1)
#   A5:    rapor doktor branşı (5 uzmandan biri)
#   A6:    reçete hekim branşı (aynı 5 uzmandan biri)
#   A7:    rapor süresi ≤ 6 ay
#   A8:    toplam tedavi başlangıçtan itibaren ≤ 6 ay

_HEMANJIYOM_YETKILI_BRANSLAR = (
    'COCUK HEMATOLOJI VE ONKOLOJI', 'ÇOCUK HEMATOLOJI VE ONKOLOJI',
    'ÇOCUK HEMATOLOJİ VE ONKOLOJİ',
    'COCUK HEMATOLOJI', 'ÇOCUK HEMATOLOJI', 'ÇOCUK HEMATOLOJİ',
    'PEDIATRIK HEMATOLOJI', 'PEDİATRİK HEMATOLOJİ',
    'COCUK ONKOLOJI', 'ÇOCUK ONKOLOJI', 'ÇOCUK ONKOLOJİ',
    'PEDIATRIK ONKOLOJI', 'PEDİATRİK ONKOLOJİ',
    'COCUK KARDIYOLOJI', 'ÇOCUK KARDIYOLOJI', 'ÇOCUK KARDİYOLOJİ',
    'PEDIATRIK KARDIYOLOJI', 'PEDİATRİK KARDİYOLOJİ',
    'NEONATOLOJI', 'NEONATOLOJİ',
    'YENIDOGAN', 'YENİDOĞAN',
)


def _hemanjiyom_dogum_tarihi_oku(ilac_sonuc: Dict):
    """Hasta doğum tarihini date olarak döndür (gün hesabı için).

    Dönüş: datetime.date veya None. Rapor metninden yaş okunmaz (DB-only).
    """
    from datetime import date, datetime
    dogum = (ilac_sonuc.get('dogum_tarihi') or
             ilac_sonuc.get('hasta_dogum_tarihi'))
    if isinstance(dogum, date):
        return dogum
    if not dogum:
        return None
    s = str(dogum).strip()
    for fmt in ('%Y-%m-%d', '%d.%m.%Y', '%d/%m/%Y', '%Y/%m/%d',
                '%Y-%m-%dT%H:%M:%S', '%Y-%m-%d %H:%M:%S'):
        try:
            return datetime.strptime(s[:len(fmt) + 4], fmt).date()
        except ValueError:
            continue
    return None


def _hemanjiyom_atom_yas_araligi(ilac_sonuc: Dict) -> SartSonuc:
    """A1+A2: Yaş 5 hafta (≥35 gün) — 5 ay (≤ ~152 gün, takvim ayı).

    Rapor metni KULLANILMAZ. Hasta doğum tarihi yoksa KE.
    hasta_yasi yıl bazlı kalırsa: 0 yıl gelirse "5 ay altı olabilir" ama
    netleştirilemez → KE; 1+ yıl gelirse açıkça yaş üst sınırı aşıldı → YOK.
    """
    from datetime import date
    grup = 'Yaş aralığı'
    ad = 'Hasta 5 hafta – 5 ay aralığında'

    dogum = _hemanjiyom_dogum_tarihi_oku(ilac_sonuc)
    if dogum is not None:
        bugun = date.today()
        gun = (bugun - dogum).days
        # 5 hafta = 35 gün; 5 ay ≈ takvim olarak doğum + 5 ay
        # Gün toleransı: 5 takvim ayı = 5 * 30.4375 ≈ 152 gün; üst sınır 153
        if gun < 35:
            return SartSonuc(ad, SartDurumu.YOK,
                             f'Hasta yaşı {gun} gün — alt sınır 35 gün (5 hafta)',
                             kaynak='dogum_tarihi', grup=grup)
        if gun > 153:
            return SartSonuc(ad, SartDurumu.YOK,
                             f'Hasta yaşı {gun} gün (~{gun // 30} ay) — üst sınır 5 ay',
                             kaynak='dogum_tarihi', grup=grup)
        hafta = gun // 7
        return SartSonuc(ad, SartDurumu.VAR,
                         f'Hasta yaşı {gun} gün (~{hafta} hafta) — aralıkta',
                         kaynak='dogum_tarihi', grup=grup)

    # Fallback: hasta_yasi (yıl). 0 yıl belirsiz; ≥1 yıl açıkça dışında.
    hy = ilac_sonuc.get('hasta_yasi') or ilac_sonuc.get('yas')
    try:
        yas_yil = int(re.sub(r'[^0-9]', '', str(hy or '')) or -1)
    except (ValueError, TypeError):
        yas_yil = -1
    if yas_yil >= 1:
        return SartSonuc(ad, SartDurumu.YOK,
                         f'Hasta yaşı {yas_yil} yıl — 5 ay üstü',
                         kaynak='hasta_yasi', grup=grup)
    return SartSonuc(
        ad, SartDurumu.KONTROL_EDILEMEDI,
        'Doğum tarihi DB\'de yok — gün/hafta hesaplanamadı, manuel doğrulanmalı',
        kaynak='hasta_yasi/dogum_tarihi', grup=grup)


def _hemanjiyom_atom_endikasyon(metin_lower: str,
                                  teshis_metin: str) -> SartSonuc:
    """A3: Sistemik tedavi gerektiren / morbidite riski hemanjiyom.

    Pozitif ibareler: 'hemanjiyom', 'hemangioma', 'hemanjioma'.
    Morbidite anahtarları: yutma güçlüğü, kanama, bası, solunum güçlüğü,
    sistemik tedavi, hızla çoğal/büyü.
    """
    grup = 'Endikasyon'
    ad = 'Çocukluk çağı hemanjiyomu (sistemik tedavi gerektiren)'

    hem_var = ('hemanjiyom' in metin_lower or 'hemangiyoma' in metin_lower
               or 'hemanjioma' in metin_lower or 'hemangioma' in metin_lower
               or 'hemanjiom' in metin_lower
               or 'D18' in (teshis_metin or '').upper())
    if not hem_var:
        return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                         'Rapor metninde "hemanjiyom" ibaresi bulunamadı',
                         kaynak='rapor_metni', grup=grup)
    morbidite_anahtarlari = (
        'yutma güçl', 'yutma gucl', 'kanama', 'bası bulgu', 'basi bulgu',
        'solunum güçl', 'solunum gucl', 'sistemik tedavi',
        'hızla çoğal', 'hizla cogal', 'hızla büyü', 'hizla buyu',
        'morbidite',
    )
    eslesen = [k for k in morbidite_anahtarlari if k in metin_lower]
    if eslesen:
        return SartSonuc(ad, SartDurumu.VAR,
                         f'Hemanjiyom + morbidite ibaresi: {", ".join(eslesen[:3])}',
                         kaynak='rapor_metni', grup=grup)
    return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                     'Hemanjiyom geçiyor ama morbidite ibaresi netleşmedi — manuel doğrulanmalı',
                     kaynak='rapor_metni', grup=grup)


def _hemanjiyom_atom_alt_madde_a(metin_lower: str) -> SartSonuc:
    """A4a: Hayatı veya hayati fonksiyonu tehdit edici hemanjiyom."""
    grup = 'Alt madde (a/b/c — ≥1)'
    ad = '(a) Hayatı/hayati fonksiyonu tehdit edici'
    anahtarlar = (
        'hayatı tehdit', 'hayati tehdit', 'hayat tehdit',
        'hayati fonksiyon', 'hayatı fonksiyon',
        'life threat', 'organ tehdit',
        'havayolu', 'havayolunu',
    )
    eslesen = [k for k in anahtarlar if k in metin_lower]
    if eslesen:
        return SartSonuc(ad, SartDurumu.VAR,
                         f'İbare: {", ".join(eslesen[:2])}',
                         kaynak='rapor_metni', grup=grup, veya_grubu=True)
    return SartSonuc(ad, SartDurumu.YOK,
                     'Rapor lafzında hayat tehdidi ibaresi yok',
                     kaynak='rapor_metni', grup=grup, veya_grubu=True)


def _hemanjiyom_atom_alt_madde_b(metin_lower: str) -> SartSonuc:
    """A4b: Ağrılı ve/veya yara bakım tedavilerine yanıtsız ülsere hemanjiyom."""
    grup = 'Alt madde (a/b/c — ≥1)'
    ad = '(b) Ülsere + yara bakımına yanıtsız / ağrılı'
    ulsere = ('ülsere' in metin_lower or 'ulsere' in metin_lower
              or 'ülser' in metin_lower)
    agri = ('ağrı' in metin_lower or 'agri' in metin_lower
            or 'ağrılı' in metin_lower)
    yanitsiz = ('yanıt verme' in metin_lower or 'yanit verme' in metin_lower
                or 'yanıtsız' in metin_lower or 'yanitsiz' in metin_lower
                or 'cevapsız' in metin_lower or 'cevapsiz' in metin_lower)
    if ulsere and (agri or yanitsiz):
        return SartSonuc(ad, SartDurumu.VAR,
                         f'Ülsere + {"ağrılı" if agri else "yanıtsız"}',
                         kaynak='rapor_metni', grup=grup, veya_grubu=True)
    if ulsere:
        return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                         'Ülsere geçiyor ama ağrı/yara bakımı yanıtsızlığı netleşmedi',
                         kaynak='rapor_metni', grup=grup, veya_grubu=True)
    return SartSonuc(ad, SartDurumu.YOK,
                     'Ülsere hemanjiyom ibaresi yok',
                     kaynak='rapor_metni', grup=grup, veya_grubu=True)


def _hemanjiyom_atom_alt_madde_c(metin_lower: str) -> SartSonuc:
    """A4c: Kalıcı yara izi / şekil bozukluğu riski."""
    grup = 'Alt madde (a/b/c — ≥1)'
    ad = '(c) Kalıcı yara izi / şekil bozukluğu riski'
    anahtarlar = (
        'kalıcı yara', 'kalici yara', 'yara izi', 'iz riski',
        'şekil bozukl', 'sekil bozukl', 'deformi', 'estetik',
        'kalıcı iz', 'kalici iz', 'kozmetik',
    )
    eslesen = [k for k in anahtarlar if k in metin_lower]
    if eslesen:
        return SartSonuc(ad, SartDurumu.VAR,
                         f'İbare: {", ".join(eslesen[:2])}',
                         kaynak='rapor_metni', grup=grup, veya_grubu=True)
    return SartSonuc(ad, SartDurumu.YOK,
                     'Rapor lafzında kalıcı yara izi/şekil bozukluğu ibaresi yok',
                     kaynak='rapor_metni', grup=grup, veya_grubu=True)


def _hemanjiyom_brans_yetkili_mi(brans: str) -> bool:
    if not brans:
        return False
    b = (brans or '').upper().strip()
    return any(k in b for k in _HEMANJIYOM_YETKILI_BRANSLAR)


def _hemanjiyom_atom_rapor_brans(ilac_sonuc: Dict) -> SartSonuc:
    """A5: Rapor doktor branşı 5 uzmandan biri.

    Rapor kodu eşleşmesi (02.x = onkoloji, 05.x = pediatri+kardiyo)
    yardımcı kanıt olarak değerlendirilebilir ama branş tek başına
    karar verir.
    """
    grup = 'Yetki — rapor'
    ad = 'Rapor doktor branşı (çocuk hem-onk/hem/onk/kard/neonatoloji)'
    brans = (ilac_sonuc.get('doktor_uzmanligi') or
             ilac_sonuc.get('doktor_brans') or '').strip()
    if not brans:
        return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                         'Rapor doktor branşı boş — manuel doğrulanmalı',
                         kaynak='doktor_brans', grup=grup)
    if _hemanjiyom_brans_yetkili_mi(brans):
        return SartSonuc(ad, SartDurumu.VAR,
                         f'Yetkili branş: {brans}',
                         kaynak='doktor_brans', grup=grup)
    return SartSonuc(ad, SartDurumu.YOK,
                     f'Branş "{brans}" — yetkili 5 uzman dışında',
                     kaynak='doktor_brans', grup=grup)


def _hemanjiyom_atom_recete_hekim(ilac_sonuc: Dict) -> SartSonuc:
    """A6: Reçete hekim branşı aynı 5 uzmandan biri.

    `recete_hekim_uzmanligi` doluysa onu kullan; yoksa fallback olarak
    rapor doktor branşı (genelde aynı kişi).
    """
    grup = 'Yetki — reçete'
    ad = 'Reçete hekim branşı (aynı 5 uzman)'
    brans = (ilac_sonuc.get('recete_hekim_uzmanligi') or
             ilac_sonuc.get('recete_hekim_brans') or '').strip()
    if not brans:
        rapor_brans = (ilac_sonuc.get('doktor_uzmanligi') or
                       ilac_sonuc.get('doktor_brans') or '').strip()
        if rapor_brans and _hemanjiyom_brans_yetkili_mi(rapor_brans):
            return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                             f'Reçete hekim branşı boş; rapor doktoru ({rapor_brans}) '
                             'yetkili ama reçete eden farklı olabilir — manuel doğrula',
                             kaynak='recete_hekim_brans', grup=grup)
        return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                         'Reçete hekim branşı bilgisi yok — manuel doğrulanmalı',
                         kaynak='recete_hekim_brans', grup=grup)
    if _hemanjiyom_brans_yetkili_mi(brans):
        return SartSonuc(ad, SartDurumu.VAR,
                         f'Yetkili branş: {brans}',
                         kaynak='recete_hekim_brans', grup=grup)
    return SartSonuc(ad, SartDurumu.YOK,
                     f'Branş "{brans}" — yetkili 5 uzman dışında',
                     kaynak='recete_hekim_brans', grup=grup)


def _hemanjiyom_atom_rapor_suresi(ilac_sonuc: Dict,
                                    metin_lower: str) -> SartSonuc:
    """A7: Rapor süresi ≤ 6 ay.

    Tarih alanlarından (rapor_baslangic_tarihi / rapor_bitis_tarihi)
    hesapla. Yoksa rapor metninde '6 ay' / '180 gün' ibaresine bak.
    """
    from datetime import date, datetime
    grup = 'Süre — rapor'
    ad = 'Rapor süresi ≤ 6 ay'

    bas = (ilac_sonuc.get('rapor_baslangic_tarihi') or
           ilac_sonuc.get('rapor_bas_tarihi'))
    bit = (ilac_sonuc.get('rapor_bitis_tarihi') or
           ilac_sonuc.get('rapor_son_tarihi'))

    def _parse(d):
        if isinstance(d, date):
            return d
        if not d:
            return None
        s = str(d).strip()
        for fmt in ('%Y-%m-%d', '%d.%m.%Y', '%d/%m/%Y',
                    '%Y-%m-%dT%H:%M:%S', '%Y-%m-%d %H:%M:%S'):
            try:
                return datetime.strptime(s[:len(fmt) + 4], fmt).date()
            except ValueError:
                continue
        return None

    d_bas, d_bit = _parse(bas), _parse(bit)
    if d_bas and d_bit:
        gun = (d_bit - d_bas).days
        if gun <= 186:  # 6 ay + birkaç gün tolerans
            return SartSonuc(ad, SartDurumu.VAR,
                             f'Rapor süresi {gun} gün — 6 ay limitini aşmıyor',
                             kaynak='rapor_tarihleri', grup=grup)
        return SartSonuc(ad, SartDurumu.YOK,
                         f'Rapor süresi {gun} gün — 6 aydan uzun',
                         kaynak='rapor_tarihleri', grup=grup)

    # Metinden ipucu
    m = re.search(r'(?:rapor.{0,15})?(\d{1,2})\s*ay\b', metin_lower)
    if m:
        try:
            ay = int(m.group(1))
            if ay <= 6:
                return SartSonuc(ad, SartDurumu.VAR,
                                 f'Rapor metni: "{ay} ay" — limitte',
                                 kaynak='rapor_metni', grup=grup)
            return SartSonuc(ad, SartDurumu.YOK,
                             f'Rapor metni: "{ay} ay" — 6 ay limitinin üstünde',
                             kaynak='rapor_metni', grup=grup)
        except ValueError:
            pass
    return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                     'Rapor başlangıç/bitiş tarihleri DB\'de yok ve metinde '
                     'süre ibaresi netleşmedi — manuel doğrulanmalı',
                     kaynak='rapor_tarihleri', grup=grup, sartli_atom=True)


def _hemanjiyom_atom_toplam_tedavi(ilac_sonuc: Dict) -> SartSonuc:
    """A8: Tedavi başlangıcından itibaren toplam ≤ 6 ay.

    Hasta ilaç geçmişinde ilk HEMANGIOL kullanım tarihi varsa onunla
    bugünün farkı hesaplanır. Pipeline'da yoksa şartlı atom (KE).
    """
    from datetime import date, datetime
    grup = 'Süre — tedavi'
    ad = 'Toplam tedavi süresi ≤ 6 ay (başlangıçtan)'

    ilac_gecmisi = ilac_sonuc.get('hasta_ilac_gecmisi') or \
                   ilac_sonuc.get('ilac_kullanim_gecmisi') or []
    ilk_tarih = None
    if isinstance(ilac_gecmisi, list):
        for kayit in ilac_gecmisi:
            if not isinstance(kayit, dict):
                continue
            ad_g = str(kayit.get('ilac_adi') or '').upper()
            et_g = str(kayit.get('etkin_madde') or '').upper()
            if 'HEMANGIOL' in ad_g or (
                    'PROPRANOLOL' in (ad_g + et_g)
                    and any(f in ad_g for f in _CESITLI_HEMANJIYOM_FORM_IBARELERI)):
                t = kayit.get('tarih') or kayit.get('ilk_tarih') or \
                    kayit.get('recete_tarihi')
                if not t:
                    continue
                if isinstance(t, date):
                    dt = t
                else:
                    dt = None
                    for fmt in ('%Y-%m-%d', '%d.%m.%Y', '%d/%m/%Y'):
                        try:
                            dt = datetime.strptime(str(t)[:10], fmt).date()
                            break
                        except ValueError:
                            continue
                if dt and (ilk_tarih is None or dt < ilk_tarih):
                    ilk_tarih = dt

    if ilk_tarih is not None:
        gun = (date.today() - ilk_tarih).days
        if gun <= 186:
            kalan = 186 - gun
            return SartSonuc(ad, SartDurumu.VAR,
                             f'İlk HEMANGIOL: {ilk_tarih.isoformat()} '
                             f'({gun} gün geçti, ~{kalan} gün kalan)',
                             kaynak='ilac_gecmisi', grup=grup)
        return SartSonuc(ad, SartDurumu.YOK,
                         f'İlk HEMANGIOL: {ilk_tarih.isoformat()} '
                         f'({gun} gün geçti — 6. ayın sonunda tedavi sonlandırılır)',
                         kaynak='ilac_gecmisi', grup=grup)

    return SartSonuc(ad, SartDurumu.KONTROL_EDILEMEDI,
                     'Hasta ilaç geçmişinde HEMANGIOL kaydı yok — '
                     'ilk reçete tarihi manuel doğrulanmalı',
                     kaynak='ilac_gecmisi', grup=grup, sartli_atom=True)


def _hemanjiyom_genel_sonuc(sartlar: List[SartSonuc]) -> Tuple[KontrolSonucu, str]:
    """8 atom sonucundan genel kararı üret.

    Mantık:
      - Yaş atomu YOK → UYGUN_DEGIL (kesin dışında)
      - Endikasyon YOK → UYGUN_DEGIL
      - Alt madde grubu (≥1) hiç VAR yok ve hiç KE yok → UYGUN_DEGIL
      - Branş atomlarından (A5+A6) ikisi de YOK → UYGUN_DEGIL
      - Herhangi bir AND atomu YOK → UYGUN_DEGIL
      - KE varsa ve KE'lerin tümü sartli_atom → SARTLI_UYGUN
      - KE varsa ve KE'lerden biri sartli değil → KONTROL_EDILEMEDI (ŞÜPHELİ)
      - Hepsi VAR → UYGUN
    """
    yas = next((s for s in sartlar if s.grup == 'Yaş aralığı'), None)
    endik = next((s for s in sartlar if s.grup == 'Endikasyon'), None)
    alt_grup = [s for s in sartlar if s.grup.startswith('Alt madde')]
    yetki_rapor = next((s for s in sartlar if s.grup == 'Yetki — rapor'), None)
    yetki_rec = next((s for s in sartlar if s.grup == 'Yetki — reçete'), None)

    if yas and yas.durum == SartDurumu.YOK:
        return (KontrolSonucu.UYGUN_DEGIL,
                f'Yaş aralığı dışında: {yas.neden}')
    if endik and endik.durum == SartDurumu.YOK:
        return (KontrolSonucu.UYGUN_DEGIL,
                'Hemanjiyom endikasyonu bulunamadı')
    if alt_grup:
        alt_var = any(s.durum == SartDurumu.VAR for s in alt_grup)
        alt_ke = any(s.durum == SartDurumu.KONTROL_EDILEMEDI for s in alt_grup)
        if not alt_var and not alt_ke:
            return (KontrolSonucu.UYGUN_DEGIL,
                    'Alt madde (a/b/c) hiçbiri rapor lafzında bulunamadı')

    # Branş kontrolü: A5 ve A6 yan yana — ikisi de YOK → kesin
    if (yetki_rapor and yetki_rapor.durum == SartDurumu.YOK and
            yetki_rec and yetki_rec.durum == SartDurumu.YOK):
        return (KontrolSonucu.UYGUN_DEGIL,
                'Rapor ve reçete hekim branşları yetkili 5 uzman dışında')

    # AND atomlarından biri YOK?
    and_yok = [s for s in sartlar
               if s.durum == SartDurumu.YOK and not s.veya_grubu]
    if and_yok:
        return (KontrolSonucu.UYGUN_DEGIL,
                'Bir veya daha fazla zorunlu şart sağlanmıyor: '
                + ', '.join(s.ad for s in and_yok[:3]))

    # KE atomları
    ke = [s for s in sartlar if s.durum == SartDurumu.KONTROL_EDILEMEDI]
    if ke:
        if all(s.sartli_atom for s in ke):
            return (KontrolSonucu.SARTLI_UYGUN,
                    'Hesaplanabilir şartlar UYGUN; manuel doğrulanması gereken: '
                    + ', '.join(s.ad for s in ke[:3]))
        return (KontrolSonucu.KONTROL_EDILEMEDI,
                'Bazı şartlar netleşmedi: '
                + ', '.join(s.ad for s in ke[:3]))

    return (KontrolSonucu.UYGUN,
            'SUT 4.2.62 — tüm şartlar sağlanıyor (HEMANGIOL bebek hemanjiyomu)')


def kontrol_cesitli_hemanjiyom_4_2_62(ilac_sonuc: Dict) -> KontrolRaporu:
    """SUT 4.2.62 — Propranolol HCl oral çözelti (HEMANGIOL) atomik kontrolü.

    8 atomik şart (devre şeması):
      A1+A2: yaş 5 hafta - 5 ay (AND)
      A3:    sistemik tedavi gerektiren hemanjiyom endikasyonu (AND)
      A4a:   hayat tehdidi (VEYA ≥1)
      A4b:   ülsere + yanıtsız (VEYA ≥1)
      A4c:   kalıcı iz/şekil bozukluğu (VEYA ≥1)
      A5:    rapor doktor branşı (5 uzmandan biri, AND)
      A6:    reçete hekim branşı (aynı 5 uzman, AND)
      A7:    rapor süresi ≤ 6 ay (AND, şartlı)
      A8:    toplam tedavi ≤ 6 ay (AND, şartlı — hasta geçmişi)
    """
    sut_kurali = 'SUT 4.2.62 — Propranolol HCl oral çözelti (bebek hemanjiyomu)'
    metin = _tum_metinleri_birlesir(ilac_sonuc) or ''
    metin_lower = _tr_lower(metin)
    teshis_metin = ' '.join(ilac_sonuc.get('recete_teshisleri', []) or [])
    if not teshis_metin:
        teshis_metin = ilac_sonuc.get('teshis_metin', '') or ''

    sartlar: List[SartSonuc] = []
    sartlar.append(_hemanjiyom_atom_yas_araligi(ilac_sonuc))
    sartlar.append(_hemanjiyom_atom_endikasyon(metin_lower, teshis_metin))
    sartlar.append(_hemanjiyom_atom_alt_madde_a(metin_lower))
    sartlar.append(_hemanjiyom_atom_alt_madde_b(metin_lower))
    sartlar.append(_hemanjiyom_atom_alt_madde_c(metin_lower))
    sartlar.append(_hemanjiyom_atom_rapor_brans(ilac_sonuc))
    sartlar.append(_hemanjiyom_atom_recete_hekim(ilac_sonuc))
    sartlar.append(_hemanjiyom_atom_rapor_suresi(ilac_sonuc, metin_lower))
    sartlar.append(_hemanjiyom_atom_toplam_tedavi(ilac_sonuc))

    sonuc, mesaj = _hemanjiyom_genel_sonuc(sartlar)

    detaylar = {
        'alt_grup': 'HEMANJIYOM',
        'sut_maddesi': '4.2.62',
        'ilac_adi': (ilac_sonuc.get('ilac_adi') or '').upper(),
        'etkin_madde': (ilac_sonuc.get('etkin_madde') or '').upper(),
        'doktor_brans': (ilac_sonuc.get('doktor_uzmanligi') or '').strip(),
        'recete_hekim': (ilac_sonuc.get('recete_hekim_uzmanligi') or '').strip(),
        'sart_sayisi': len(sartlar),
        'verdict_sartlar': [
            {'ad': s.ad, 'durum': s.durum.value, 'neden': s.neden,
             'kaynak': s.kaynak, 'grup': s.grup, 'veya_grubu': s.veya_grubu,
             'sartli_atom': s.sartli_atom}
            for s in sartlar
        ],
    }

    return KontrolRaporu(
        sonuc=sonuc,
        mesaj=mesaj,
        detaylar=detaylar,
        sut_kurali=sut_kurali,
        aranan_ibare='5 hafta-5 ay bebek + hemanjiyom + uzman branş',
        sartlar=sartlar,
    )


# ═══════════════════════════════════════════════════════════════════════
# GRUP → alt_grup eşlemesi (2026-06-04 yeniden gruplama)
# ═══════════════════════════════════════════════════════════════════════
# ÇEŞİTLİ altındaki 15 alt-kontrol klinik alana göre müstakil butonlara
# dağıtıldı. Modüller değişmedi; her grup dispatcher'ı _cesitli_alt_grup_tespit
# ile alt_grup'u bulup üyelik kontrolünden sonra ortak _cesitli_route'a yönlendirir.
GRUP_UROLOJI_ALT = {'BPH', 'FINDUT', 'ALPROSTADIL', 'URINER', 'DESMOPRESSIN',
                    'PENTOSAN'}
GRUP_GOZ_ALT = {'GLOKOM', 'GOZYASI'}
GRUP_DEMANS_ALT = {'DEMANS_ALS', 'GINKGO'}
GRUP_KT_ANTIEMETIK_ALT = {'APREPITANT', 'SETRON'}
GRUP_CESITLI_KALAN_ALT = {'HEMANJIYOM', 'FLUDROKORTIZON', 'IVERMEKTIN', 'MEKLOZIN',
                          'LEFLUNOMID', 'ORLISTAT', 'PIMTAK', 'ANTIFUNGAL'}
# RANOLAZIN → ❤️ İSKEMİK KALP butonu; ATOMOKSETIN → 🧠 PSİKİYATRİ/NÖROLOJİ butonu
# (bu iki alt_grup mevcut butonların akışında işlenir, grup setlerine konmaz).


def _cesitli_route(alt_grup: str, ilac_sonuc: Dict) -> KontrolRaporu:
    """Tek alt_grup → ilgili modül entrypoint'i. Tüm grup dispatcher'ları ve
    ÇEŞİTLİ butonu bu ortak yönlendiriciyi kullanır."""
    if alt_grup == 'URINER':
        return kontrol_cesitli_madde_45_uriner(ilac_sonuc)
    if alt_grup == 'GOZYASI':
        return kontrol_cesitli_suni_gozyasi(ilac_sonuc)
    if alt_grup == 'BPH':
        return kontrol_cesitli_bph_alfa_bloker(ilac_sonuc)
    if alt_grup == 'RANOLAZIN':
        return kontrol_ranolazin(ilac_sonuc)
    if alt_grup == 'HEMANJIYOM':
        return kontrol_cesitli_hemanjiyom_4_2_62(ilac_sonuc)
    if alt_grup == 'ALPROSTADIL':
        from recete_kontrol.alprostadil_ek4f_37_1 import (
            alprostadil_kontrol_ek4f_37_1)
        return alprostadil_kontrol_ek4f_37_1(ilac_sonuc)
    if alt_grup == 'APREPITANT':
        from recete_kontrol.aprepitant_kt_bulanti import (
            aprepitant_kontrol_kt_bulanti)
        return aprepitant_kontrol_kt_bulanti(ilac_sonuc)
    if alt_grup == 'GLOKOM':
        from recete_kontrol.glokom_4_2_11 import glokom_kontrol_4_2_11
        return glokom_kontrol_4_2_11(ilac_sonuc)
    if alt_grup == 'ATOMOKSETIN':
        from recete_kontrol.atomoksetin_dehb import atomoksetin_kontrol_dehb
        return atomoksetin_kontrol_dehb(ilac_sonuc)
    if alt_grup == 'DESMOPRESSIN':
        from recete_kontrol.desmopressin_kontrol import desmopressin_kontrol
        return desmopressin_kontrol(ilac_sonuc)
    if alt_grup == 'DEMANS_ALS':
        from recete_kontrol.demans_als_ek4f_7 import demans_als_kontrol_ek4f_7
        return demans_als_kontrol_ek4f_7(ilac_sonuc)
    if alt_grup == 'FINDUT':
        from recete_kontrol.finasterid_dutasterid_bph import (
            finasterid_dutasterid_kontrol)
        return finasterid_dutasterid_kontrol(ilac_sonuc)
    if alt_grup == 'FLUDROKORTIZON':
        from recete_kontrol.fludrokortizon_ek4f_77 import (
            fludrokortizon_kontrol_ek4f_77)
        return fludrokortizon_kontrol_ek4f_77(ilac_sonuc)
    if alt_grup == 'LEFLUNOMID':
        from recete_kontrol.leflunomid_4_2_1_a import leflunomid_kontrol_4_2_1_a
        return leflunomid_kontrol_4_2_1_a(ilac_sonuc)
    if alt_grup == 'IVERMEKTIN':
        from recete_kontrol.ivermektin_ek4f import ivermektin_kontrol_ek4f
        return ivermektin_kontrol_ek4f(ilac_sonuc)
    if alt_grup == 'MEKLOZIN':
        from recete_kontrol.meklozin_antiemetik import meklozin_kontrol
        return meklozin_kontrol(ilac_sonuc)
    if alt_grup == 'ORLISTAT':
        from recete_kontrol.orlistat_4_2_18 import orlistat_kontrol_4_2_18
        return orlistat_kontrol_4_2_18(ilac_sonuc)
    if alt_grup == 'PENTOSAN':
        from recete_kontrol.pentosan_ek4f_69 import pentosan_kontrol_ek4f_69
        return pentosan_kontrol_ek4f_69(ilac_sonuc)
    if alt_grup == 'PIMTAK':
        from recete_kontrol.pimekrolimus_takrolimus_4_2_58 import pimtak_kontrol_4_2_58
        return pimtak_kontrol_4_2_58(ilac_sonuc)
    if alt_grup == 'ANTIFUNGAL':
        from recete_kontrol.antifungal_4_2_23 import antifungal_kontrol_4_2_23
        return antifungal_kontrol_4_2_23(ilac_sonuc)
    if alt_grup == 'GINKGO':
        from recete_kontrol.ginkgo_ek4f_55 import ginkgo_kontrol_ek4f_55
        return ginkgo_kontrol_ek4f_55(ilac_sonuc)
    if alt_grup == 'SETRON':
        from recete_kontrol.setron_ek4f_11 import setron_kontrol_ek4f_11
        return setron_kontrol_ek4f_11(ilac_sonuc)
    return KontrolRaporu(
        sonuc=KontrolSonucu.ATLANDI,
        mesaj='Kapsam dışı ilaç',
        detaylar={'alt_grup': 'NONE'},
        sut_kurali='ÇEŞİTLİ / grup kontrolleri')


def _grup_kontrol(ilac_sonuc: Dict, izinli_alt: set, grup_etiket: str) -> KontrolRaporu:
    """Ortak grup gate: alt_grup izinli sette ise route et, değilse ATLANDI."""
    alt_grup = _cesitli_alt_grup_tespit(
        ilac_sonuc.get('ilac_adi', '') or '',
        ilac_sonuc.get('etkin_madde', '') or '',
        ilac_sonuc.get('atc_kodu', '') or '',
    )
    if alt_grup not in izinli_alt:
        return KontrolRaporu(
            sonuc=KontrolSonucu.ATLANDI,
            mesaj=f'{grup_etiket} kapsamında olmayan ilaç',
            detaylar={'alt_grup': 'NONE'}, sut_kurali=grup_etiket)
    return _cesitli_route(alt_grup, ilac_sonuc)


def kontrol_cesitli(ilac_sonuc: Dict) -> KontrolRaporu:
    """🧪 ÇEŞİTLİ butonu — kalan niş kontroller (Hemanjiyom 4.2.62 + Fludrokortizon
    EK-4/F m.77 + İvermektin EK-4/F). Diğer eski alt-gruplar 2026-06-04'te müstakil
    butonlara taşındı."""
    return _grup_kontrol(ilac_sonuc, GRUP_CESITLI_KALAN_ALT, 'ÇEŞİTLİ')


def kontrol_uroloji(ilac_sonuc: Dict) -> KontrolRaporu:
    """🚹 ÜROLOJİ/GENİTOÜRİNER — BPH α-bloker + Finasterid/Dutasterid +
    Alprostadil + Üriner inkontinans (M.45) + Desmopressin."""
    return _grup_kontrol(ilac_sonuc, GRUP_UROLOJI_ALT, 'ÜROLOJİ')


def kontrol_goz(ilac_sonuc: Dict) -> KontrolRaporu:
    """👁️ GÖZ — Glokom (4.2.11) + Suni gözyaşı (M.2)."""
    return _grup_kontrol(ilac_sonuc, GRUP_GOZ_ALT, 'GÖZ')


def kontrol_demans(ilac_sonuc: Dict) -> KontrolRaporu:
    """🧠 DEMANS/NÖRODEJENERATİF — Donepezil/Memantin/Rivastigmin/Galantamin/
    Riluzol (m.7) + Ginkgo (m.55)."""
    return _grup_kontrol(ilac_sonuc, GRUP_DEMANS_ALT, 'DEMANS')


def kontrol_kt_antiemetik(ilac_sonuc: Dict) -> KontrolRaporu:
    """🤮 KT ANTİEMETİK — Aprepitant (NK1) + Setron (5-HT3, m.11)."""
    return _grup_kontrol(ilac_sonuc, GRUP_KT_ANTIEMETIK_ALT, 'KT ANTİEMETİK')


# CESITLI_HEMANJIYOM (SUT 4.2.62) — KATEGORI dispatcher'a runtime'da bağlanır
# (fonksiyon yukarıdaki literal sonrasında tanımlandığı için).
KATEGORI_KONTROL_FONKSIYONU['CESITLI_HEMANJIYOM'] = kontrol_cesitli_hemanjiyom_4_2_62
KATEGORI_ISIMLERI['CESITLI_HEMANJIYOM'] = (
    'Hemanjiyom — Propranolol oral çözelti / HEMANGIOL (4.2.62)'
)
